/* ============ DỮ LIỆU MỞ RỘNG — NGHĨA CHUYÊN SÂU THEO LĨNH VỰC ============ */
/* TAROT_EXT: cùng thứ tự với TAROT. ty=tình yêu, cv=công việc, tc=tài chính, sk=sức khoẻ */
const TAROT_EXT = [
{ty:"Một mối quan hệ mới đầy hứng khởi, hoặc giai đoạn mới mẻ trong tình yêu cũ; yêu bằng sự hồn nhiên, không toan tính. Người độc thân: cứ mở lòng, đừng đặt điều kiện quá sớm.",cv:"Khởi nghiệp, đổi nghề, nhận vai trò chưa từng làm. Thiếu kinh nghiệm không phải rào cản — nhiệt huyết và tinh thần học hỏi chính là vốn của bạn lúc này.",tc:"Cơ hội tài chính mới nhưng chưa có nền; hãy thử với số vốn nhỏ, chừa đường lui. Tránh dốc hết túi vào một cú nhảy.",sk:"Năng lượng tươi mới, hợp bắt đầu thói quen vận động mới; chú ý bất cẩn nhỏ gây trầy xước, vấp ngã."},
{ty:"Bạn có đủ sức chủ động tạo ra mối quan hệ mình muốn: nhắn trước, tỏ ý trước, sắp xếp buổi gặp. Sức hút cá nhân đang mạnh; đừng dùng nó để thao túng.",cv:"Thời điểm ra mắt dự án, thuyết trình, đàm phán — mọi công cụ và kỹ năng đã sẵn trong tay bạn. Tập trung một mục tiêu, đừng dàn trải.",tc:"Chủ động tạo nguồn thu mới từ kỹ năng sẵn có (nghề tay trái, tư vấn). Giao dịch, ký kết thuận lợi nếu bạn chuẩn bị kỹ.",sk:"Tinh thần quyết định thể chất: đặt mục tiêu sức khoẻ cụ thể sẽ đạt được. Chú ý căng thẳng do ôm nhiều việc."},
{ty:"Có điều chưa nói ra giữa hai người; đừng ép đối phương phơi bày, hãy để thời gian hé lộ. Người độc thân: trực giác về một người là đúng — nghe nó.",cv:"Chưa phải lúc công bố kế hoạch; giữ bài, quan sát nội bộ. Có thông tin ngầm ảnh hưởng đến việc của bạn — lắng nghe nhiều hơn nói.",tc:"Có yếu tố chưa minh bạch trong giao dịch; đọc kỹ điều khoản ẩn, hỏi lại chỗ mập mờ trước khi ký.",sk:"Chú ý nội tiết, giấc ngủ, chu kỳ cơ thể; triệu chứng mơ hồ nên đi khám thay vì tự đoán."},
{ty:"Giai đoạn nuôi dưỡng ngọt ngào: quan hệ được chăm bón sẽ nở hoa; có thể liên quan tin vui thai sản hoặc bước tiến về chung sống. Hãy thể hiện yêu thương bằng chăm sóc cụ thể.",cv:"Dự án đang vào độ chín, thành quả sắp gặt; môi trường làm việc cần sự sáng tạo và bầu không khí hào phóng. Vai trò cố vấn, nuôi dưỡng đội nhóm hợp với bạn.",tc:"Tài chính sung túc dần, nguồn thu ổn định sinh sôi; hợp đầu tư vào thứ 'nuôi lớn được' (giáo dục, đất vườn, kinh doanh thực phẩm, làm đẹp).",sk:"Cơ thể cần được chiều: ăn lành, ngủ đủ, thiên nhiên. Phụ nữ chú ý sức khoẻ sinh sản theo hướng tích cực."},
{ty:"Quan hệ cần sự rõ ràng về cam kết và ranh giới; một người đáng tin, che chở nhưng có thể hơi áp đặt. Đừng biến tình yêu thành quan hệ cấp trên–cấp dưới.",cv:"Thời điểm thiết lập quy trình, kỷ luật, cơ cấu; hợp làm việc với cơ quan nhà nước, sếp lớn, hoặc chính bạn lên vai lãnh đạo. Thành công đến từ kế hoạch chứ không từ cảm hứng.",tc:"Quản lý tiền theo kỷ luật: ngân sách, sổ sách, tích sản dài hạn (bất động sản). Tránh chi tiêu cảm tính.",sk:"Duy trì lịch sinh hoạt đều đặn; chú ý xương khớp, cột sống, huyết áp — bệnh của người ngồi ghế quyền và ngồi lâu."},
{ty:"Mối quan hệ hướng về chuẩn mực: ra mắt gia đình, đính hôn, cưới hỏi theo nghi lễ. Nếu đang trục trặc, tìm người lớn hoặc chuyên gia tư vấn hôn nhân là đúng hướng.",cv:"Làm đúng quy trình, học từ người đi trước, thi lấy chứng chỉ; tổ chức lớn, trường học, tôn giáo, đoàn thể là môi trường thuận. Chưa phải lúc phá cách.",tc:"Đi đường tài chính chính thống: ngân hàng, bảo hiểm, quỹ uy tín; tránh kênh trôi nổi, lời mời 'ngoài luồng'.",sk:"Tuân thủ phác đồ, tái khám đúng hẹn; các phương pháp kinh điển hiệu quả hơn mẹo lạ trên mạng."},
{ty:"Trái tim đứng trước lựa chọn quan trọng: chọn người, hoặc chọn mức cam kết. Sự hoà hợp thật đến khi hai người thành thật về giá trị sống; tình yêu đang được thử bằng câu hỏi 'mình có cùng đường không'.",cv:"Ngã ba nghề nghiệp: hai lời mời, hai hướng đi. Chọn theo giá trị cốt lõi chứ không theo cái lợi trước mắt; hợp tác ăn ý với một người đồng điệu.",tc:"Quyết định tài chính lớn cần bàn bạc với người đồng hành; minh bạch tiền bạc trong quan hệ đôi lứa/đối tác để tránh mầm rạn nứt.",sk:"Sức khoẻ liên quan lựa chọn lối sống: đến lúc chọn dứt khoát giữa thói quen cũ hại và nếp mới lành."},
{ty:"Chủ động theo đuổi và bạn sẽ thắng; khoảng cách địa lý không phải trở ngại nếu cả hai cùng quyết. Kiểm soát cái tôi kẻo tình yêu thành cuộc đua ai thắng ai.",cv:"Giai đoạn bứt tốc: deadline gấp, dự án cần người cầm cương. Gom hai nguồn lực trái chiều về một hướng là bài toán của bạn — làm được sẽ thăng tiến rõ.",tc:"Tiến nhanh về mục tiêu tài chính nhờ kỷ luật và tốc độ; các việc liên quan xe cộ, vận chuyển, di chuyển có lộc.",sk:"Vận động mạnh hợp thời điểm; nhưng cẩn thận chấn thương do gắng quá đà và tai nạn giao thông — chạy nhanh nhưng đừng ẩu."},
{ty:"Cảm hoá bằng dịu dàng thắng mọi tranh cãi; người kiên nhẫn sẽ giữ được trái tim đối phương. Thuần phục 'con thú' trong chính mình: ghen tuông, nóng giận.",cv:"Xử lý đồng nghiệp khó, khách hàng dữ bằng mềm mỏng và bền bỉ; sức bền quan trọng hơn cú đấm. Đừng đối đầu tay đôi với người đang nóng.",tc:"Kiên trì kế hoạch dài hơi thay vì lướt sóng; thuần hoá thói quen chi tiêu bốc đồng là chìa khoá tiền bạc lúc này.",sk:"Hồi phục bền bỉ từng ngày; các liệu pháp nhẹ nhàng đều đặn (đi bộ, yoga, thở) hiệu quả hơn ép xác."},
{ty:"Cần khoảng lặng để hiểu mình muốn gì trước khi bước tiếp; độc thân giai đoạn này là chọn lựa lành mạnh, không phải thất bại. Trong quan hệ: một người cần không gian riêng — hãy tôn trọng.",cv:"Làm việc sâu một mình, nghiên cứu, viết lách, hoàn thiện chuyên môn; chưa phải lúc quảng bá. Có thể xuất hiện người thầy chỉ đường.",tc:"Rà soát lại toàn bộ tài chính trong yên tĩnh; tạm ngừng khoản đầu tư mới để nhìn lại danh mục cũ.",sk:"Cơ thể cần nghỉ và ngủ; cẩn thận suy nhược vì cô lập kéo dài — tĩnh dưỡng khác với tự giam mình."},
{ty:"Bước ngoặt duyên số: gặp gỡ định mệnh, tái hợp, hoặc chuyển giai đoạn quan hệ. Điều duy nhất nên làm là thuận theo dòng thay vì bám chặt kịch bản cũ.",cv:"Thời cuộc xoay: tái cơ cấu, đổi sếp, đổi thị trường. Người thích nghi nhanh sẽ gặp may; cơ hội đến bất ngờ — trả lời sớm.",tc:"Tài vận biến động theo chu kỳ: có lộc bất ngờ nhưng cũng đổi chiều nhanh; chốt lời khi được, đừng tin vận may kéo dài mãi.",sk:"Sức khoẻ theo nhịp chu kỳ; thời tiết giao mùa dễ ốm vặt — phòng trước một bước."},
{ty:"Sự công bằng trong quan hệ được đặt lên bàn cân: cho–nhận phải tương xứng. Liên quan giấy tờ hôn nhân (đăng ký, ly hôn, phân chia) thì kết quả sẽ đúng lẽ phải.",cv:"Hợp đồng, pháp lý, đánh giá năng lực — mọi thứ được phân xử đúng công tội. Giữ hồ sơ minh bạch; nếu bạn đúng, cứ mạnh dạn đòi quyền lợi.",tc:"Cân đối thu chi sòng phẳng, trả nợ đúng hẹn, khai báo trung thực; các vấn đề thuế, bảo hiểm, thừa kế được giải quyết đúng luật.",sk:"Cân bằng là thuốc: ăn–ngủ–làm điều độ; chú ý thận và các bệnh do mất cân bằng chuyển hoá."},
{ty:"Tình cảm đang 'treo': người kia chưa sẵn sàng, hoặc bạn đang hy sinh nhiều hơn nhận. Thử nhìn từ vị trí đối phương trước khi kết luận; chờ đợi có chủ đích khác với chờ đợi vô vọng.",cv:"Dự án bị hoãn — dùng khoảng dừng để nhìn lại cách làm từ góc hoàn toàn khác; giải pháp nằm ở chỗ bạn chưa từng đứng nhìn.",tc:"Dòng tiền tạm đóng băng; đừng bán tháo trong lúc kẹt. Đôi khi chịu thiệt nhỏ trước mắt để giữ giá trị dài hạn.",sk:"Chậm lại là mệnh lệnh của cơ thể; các vấn đề tuần hoàn, tê mỏi do sai tư thế — đổi thói quen, treo ngược góc nhìn về 'nghỉ ngơi'."},
{ty:"Một chương tình cảm khép lại dứt điểm — chia tay, hoặc cái chết của phiên bản cũ trong quan hệ để hai người bước sang giai đoạn khác hẳn. Níu kéo chỉ kéo dài cơn đau; buông đúng lúc là tự trọng.",cv:"Kết thúc công việc/dự án/vai trò cũ; tái cấu trúc mạnh. Đừng gửi CV níu vị trí đã hết duyên — cánh cửa mới chỉ mở khi cửa cũ đóng hẳn.",tc:"Cắt lỗ dứt khoát, đóng khoản đầu tư đã chết, tất toán nợ cũ; tài chính cần một cuộc 'thay máu' về cấu trúc.",sk:"Chuyển hoá lớn: bỏ hẳn một thói quen độc hại (thuốc lá, rượu, thức khuya); cơ thể tái sinh mạnh mẽ sau khi cắt bỏ."},
{ty:"Hai người khác biệt đang học pha vào nhau từng chút; kiên nhẫn và nhường nhịn đúng liều sẽ chữa lành vết cũ. Tình yêu giai đoạn này cần 'lửa nhỏ hầm lâu'.",cv:"Vai trò điều phối, dung hoà các bên hợp bạn; tiến độ vừa phải nhưng chắc. Tránh cả hai thái cực: ôm hết và buông hết.",tc:"Chiến lược trung dung: vừa tiết kiệm vừa hưởng thụ có mức; đa dạng hoá danh mục thay vì tất tay một cửa.",sk:"Phục hồi từ từ đúng liều lượng; chú ý cân bằng nước – điện giải, tiêu hoá; điều độ là toa thuốc chính."},
{ty:"Quan hệ có mùi ràng buộc không lành: ghen tuông kiểm soát, lệ thuộc, hoặc đam mê thể xác che mờ mọi thứ khác. Nhìn thẳng: xiềng xích này bạn tự đeo và tự tháo được.",cv:"Công việc lương cao nhưng rút cạn bạn, hoặc quan hệ lợi ích ngầm đang trói tay; nhận diện cái giá thật đang trả. Cẩn thận hợp đồng ràng buộc bất lợi.",tc:"Cảnh giác nợ lãi cao, cờ bạc, đầu cơ gây nghiện; ham muốn vật chất đang điều khiển quyết định. Xem lại các khoản 'trả góp cho ham muốn'.",sk:"Các thói nghiện là gốc bệnh giai đoạn này (đường, rượu, màn hình, chất kích thích); cắt cơn cần hỗ trợ, đừng tự đấu một mình."},
{ty:"Sự thật bùng ra làm rung chuyển quan hệ: bí mật lộ, vỡ mộng, chia tay đột ngột. Đau nhưng giải phóng — cái sụp là phần được xây trên nền giả; phần thật sẽ trụ lại.",cv:"Biến động lớn: mất việc, huỷ dự án, tổ chức xáo trộn. Đừng cố dựng lại y nguyên cái đã sập; thiết kế lại từ móng với bài học vừa nhận.",tc:"Cú sốc tài chính có thể xảy đến — quỹ khẩn cấp là phao. Sau đổ vỡ, cấu trúc tài chính mới sẽ vững hơn nếu bạn dám làm lại đúng cách.",sk:"Cẩn thận biến cố cấp tính (tai nạn, cơn đau đột ngột) — đừng phớt lờ dấu hiệu bất thường; khám sớm hơn kế hoạch."},
{ty:"Sau giông bão, trái tim được chữa lành; một tình cảm trong trẻo, không vụ lợi đang đến hoặc đang hồi sinh. Cứ hy vọng — lần này hy vọng có cơ sở.",cv:"Cảm hứng trở lại, được ghi nhận đúng năng lực; hợp các nghề sáng tạo, cộng đồng, thiện nguyện. Mục tiêu dài hạn sáng rõ — cắm mốc và đi.",tc:"Tài chính hồi phục dần sau giai đoạn khó; đầu tư dài hạn theo niềm tin có phân tích. Chia sẻ, cho đi lúc này lại mở lộc.",sk:"Giai đoạn hồi phục tốt lành; nước, không khí, giấc ngủ là ba vị thuốc chính. Bệnh cũ có tiến triển tích cực."},
{ty:"Mối quan hệ nhiều sương mù: mập mờ, chưa rõ danh phận, hoặc bạn đang yêu hình bóng mình tưởng tượng. Đừng quyết định lớn khi chưa nhìn rõ; hỏi thẳng những gì cần hỏi.",cv:"Thông tin nhiễu, chính trị văn phòng, lời hứa không rõ ràng; ghi lại mọi thoả thuận bằng văn bản. Trực giác báo điều gì đó chưa ổn — kiểm chứng nó.",tc:"Nguy cơ mập mờ tài chính: dự án tô vẽ, số liệu ảo, lừa đảo tinh vi. Nguyên tắc: không hiểu rõ thì không xuống tiền.",sk:"Chú ý giấc ngủ, mộng mị, lo âu; triệu chứng 'không rõ nguyên nhân' nên khám chuyên khoa và cả sức khoẻ tinh thần."},
{ty:"Tình yêu rực rỡ, hôn nhân vui, tin mừng con cái; giai đoạn hâm nóng tuyệt vời — đi chơi chung dưới nắng đúng nghĩa đen. Cứ để niềm vui dẫn đường.",cv:"Thành công công khai: dự án ra mắt thắng lợi, được khen thưởng trước tập thể; thương hiệu cá nhân toả sáng. Thời điểm vàng để xuất hiện.",tc:"Tài vận vượng, các khoản đầu tư 'ra ánh sáng' sinh lời; hợp ký kết, khai trương. Vẫn giữ một phần dự phòng — nắng to cũng cần bóng râm.",sk:"Sinh lực dồi dào, tinh thần lạc quan kéo thể chất lên; tắm nắng sớm, hoạt động ngoài trời rất hợp. Trẻ nhỏ trong nhà khoẻ vui."},
{ty:"Tiếng gọi tổng kết: tha thứ cho quá khứ, quyết định dứt khoát về một mối quan hệ cũ — tái hợp thật sự hoặc khép lại thật sự, không lơ lửng nữa.",cv:"Thời điểm đánh giá lại toàn bộ sự nghiệp và nghe 'tiếng gọi' nghề nghiệp thật của mình; kết quả xét duyệt, phỏng vấn có phán quyết rõ ràng.",tc:"Tổng kết sổ sách, quyết toán, xử lý dứt điểm nợ nần tồn đọng; sau kỳ 'phán xét' này tài chính sang trang.",sk:"Kết quả chẩn đoán rõ ràng giúp đổi hẳn lối sống; cơ thể đáp ứng tốt khi bạn thật sự quyết tâm 'sống lại lần nữa'."},
{ty:"Viên mãn một chặng: về chung nhà, kỷ niệm lớn, hoặc đạt trạng thái hài hoà hiếm có; cũng có thể là tình yêu gắn với người phương xa, khác văn hoá. Ăn mừng rồi mở chu kỳ mới.",cv:"Hoàn tất dự án lớn thành công, đạt vị trí từng nhắm; cơ hội quốc tế, thị trường mới. Trước khi nhận vai mới, khép trọn vẹn việc cũ — đừng để đuôi dang dở.",tc:"Mục tiêu tài chính cán đích: tất toán, chốt lời, đủ vốn cho kế hoạch lớn; hợp các khoản liên quan nước ngoài, xuất nhập khẩu.",sk:"Thể trạng đạt cân bằng tốt; duy trì thành quả bằng nếp đã tạo. Du lịch, thay đổi không khí giúp tái tạo sâu."},
/* ----- GẬY (Wands) ----- */
{ty:"Tia sét ái tình, đam mê bùng lên nhanh; hợp tỏ tình, hâm nóng. Đừng hứa quá sớm điều chưa chắc.",cv:"Ý tưởng/dự án mới đầy năng lượng — bắt tay ngay khi lửa còn nóng; cơ hội đến từ sự hào hứng của chính bạn.",tc:"Cơ hội kiếm tiền mới từ đam mê; vốn nhỏ khởi động được, đừng chờ 'đủ' mới làm.",sk:"Sinh lực bật tăng; kênh xả năng lượng lành mạnh (thể thao) giúp mọi mặt thăng hoa."},
{ty:"Đang cân nhắc đưa quan hệ đi xa hơn (dọn về chung, công khai); người kia chờ bạn quyết. Đứng mãi ở ban công thì thế giới không tự đến.",cv:"Lập kế hoạch mở rộng, tính chuyện thị trường xa hơn; đã đến lúc chọn một hướng và cam kết với nó.",tc:"Kế hoạch tài chính dài hạn cần được viết ra cụ thể; cân nhắc đầu tư xa (tỉnh khác, nước khác) có tính toán.",sk:"Lên kế hoạch sức khoẻ dài hạn thay vì cơn hứng ba ngày; khám tổng quát định kỳ để 'nhìn xa'."},
{ty:"Tình xa, chờ tin người ở xa, hoặc quan hệ đang chờ kết quả của một quyết định trước đó; điều bạn gieo đang trên đường về.",cv:"Thành quả bước đầu đã rời bến — chờ thuyền về; hợp tác liên tỉnh, quốc tế thuận. Chuẩn bị sẵn kịch bản đón cơ hội lớn hơn.",tc:"Khoản đầu tư bắt đầu sinh chuyển động; kiên nhẫn giữ vị thế, đồng thời chuẩn bị vốn cho đợt mở rộng.",sk:"Tiến triển tốt đang trên đường tới; duy trì phác đồ, đừng đổi ngựa giữa dòng."},
{ty:"Tin vui hỷ sự: đính hôn, cưới hỏi, tân gia, đoàn tụ; quan hệ bước vào giai đoạn ổn định ấm áp có sự chúc phúc của mọi người.",cv:"Cột mốc dự án được ăn mừng; môi trường làm việc hoà thuận. Sự kiện, lễ ra mắt tổ chức lúc này thành công.",tc:"Chi cho lễ lạt, nhà cửa là hợp lý; tài chính đủ vững cho một khoản 'xây tổ'.",sk:"Tinh thần cộng đồng nâng sức khoẻ; nhà cửa an ổn thì bệnh vặt cũng lui."},
{ty:"Va chạm, ghen đua, người thứ ba cạnh tranh hoặc cãi vã vặt; xung đột lành mạnh nếu để nó làm rõ nhu cầu mỗi người — đấu để hiểu, không phải để thắng.",cv:"Cạnh tranh nội bộ, đấu thầu, tranh luận phương án; giữ tinh thần thể thao, tập trung vào chất lượng thay vì hạ đối thủ.",tc:"Thị trường cạnh tranh giá; so sánh kỹ trước khi mua lớn, thương lượng thêm được đấy.",sk:"Căng thẳng do va chạm vặt; thể thao đối kháng là chỗ xả tuyệt vời cho năng lượng này."},
{ty:"Tình yêu được công khai và ủng hộ; sau chặng cố gắng, hai bạn 'chiến thắng' — ra mắt suôn sẻ, tỏ tình thành công.",cv:"Thắng lợi rõ ràng: trúng thầu, thăng chức, dự án được duyệt; uy tín cá nhân lên cao — tận dụng đà này để đề xuất điều bạn ấp ủ.",tc:"Khoản thưởng, khoản thắng về tay; dùng một phần củng cố nền, đừng tiêu hết cho ăn mừng.",sk:"Hồi phục thắng lợi, chỉ số cải thiện; tự tin nhưng duy trì thuốc/liệu trình đủ liều."},
{ty:"Bạn đang phải bảo vệ mối quan hệ trước lời ra tiếng vào hoặc người cũ quay lại quấy; giữ vững lập trường nếu tin vào lựa chọn của mình.",cv:"Vị trí của bạn bị cạnh tranh, ý tưởng bị thách thức; phòng thủ chủ động bằng năng lực và bằng chứng. Lợi thế cao điểm vẫn thuộc về bạn.",tc:"Bảo vệ tài sản trước đòi hỏi vay mượn, tranh chấp; đừng nhượng bộ khoản thuộc về mình một cách hợp lẽ.",sk:"Sức đề kháng đang bị thử; tăng cường miễn dịch, giữ vững nếp lành trước cám dỗ bỏ cuộc."},
{ty:"Tình cảm tăng tốc: tin nhắn dồn dập, tiến triển nhanh bất ngờ, tình yêu từ xa có tin vui; nói lời cần nói ngay đi.",cv:"Mọi việc trôi nhanh: email, phê duyệt, tin tức tới tấp; xử lý dứt điểm từng việc kẻo trôi mất cơ hội. Chuyến công tác đến gấp.",tc:"Dòng tiền luân chuyển nhanh; giao dịch chốt sớm có lợi. Cẩn thận thao tác vội gây nhầm lệnh, nhầm số.",sk:"Nhịp sống gấp — đừng bỏ bữa, thiếu ngủ; các triệu chứng diễn tiến nhanh cần khám ngay không trì hoãn."},
{ty:"Từng tổn thương nên giờ phòng thủ; đừng bắt người mới trả nợ người cũ. Quan hệ đang ở chặng mệt nhưng chỉ còn một đoạn nữa là qua dốc.",cv:"Dự án ở 90% — mệt nhất chính là lúc này; rà lại phòng ngừa rủi ro lần cuối rồi đi nốt. Đừng nhận thêm mặt trận mới.",tc:"Giữ thành quả đã tích luỹ, phòng thủ trước rủi ro cuối kỳ; chưa phải lúc mạo hiểm khoản mới.",sk:"Cơ thể báo mệt tích luỹ; kiệt sức là có thật — nghỉ chiến thuật để đi được đường dài."},
{ty:"Bạn đang gánh phần nặng trong quan hệ (tài chính, cảm xúc, gia đình hai bên); san sẻ bớt hoặc nói ra, kẻo yêu thành nghĩa vụ.",cv:"Ôm quá nhiều việc vì không dám từ chối; học uỷ quyền và nói 'không'. Sắp về đích rồi — bỏ bớt củi thừa sẽ đi nhanh hơn.",tc:"Gánh nợ/chi phí đè nặng; tái cấu trúc khoản vay, cắt chi phí cố định không cần thiết.",sk:"Quá tải thể hiện ở vai, gáy, lưng; giảm tải và vật lý trị liệu, đừng cố 'gồng nốt'."},
{ty:"Tin vui tình cảm từ người trẻ trung, nhiệt thành; giai đoạn tán tỉnh vui tươi. Nhiệt tình có thừa, độ chín cần thời gian kiểm chứng.",cv:"Tin tốt về cơ hội mới: lời mời, học bổng, dự án thử sức; nhận lấy với tinh thần học hỏi. Người trẻ trong nhóm mang ý tưởng đáng nghe.",tc:"Tin tức tích cực về tiền (khoản về, được duyệt); món đầu tư mới nên thử ở quy mô 'học phí nhỏ'.",sk:"Tinh thần trẻ trung là thuốc bổ; thử môn vận động mới cho vui để duy trì được lâu."},
{ty:"Người tình nồng nhiệt, tốc độ, thích chinh phục — cuốn hút nhưng dễ 'cháy nhanh tàn nhanh'; muốn bền phải xem hành động sau lời hứa.",cv:"Giai đoạn hành động táo bạo: đi công tác, ra mắt nhanh, chớp thời cơ; nhưng kế hoạch B phải có — tốc độ không thay được phanh.",tc:"Cơ hội lợi nhuận nhanh kèm rủi ro cao; chỉ chơi bằng phần vốn dám mất, chốt lời kỷ luật.",sk:"Năng lượng cao nhưng hấp tấp dễ chấn thương; khởi động kỹ, đeo bảo hộ, chạy xe bớt ẩu."},
{ty:"Người phụ nữ cuốn hút, tự chủ trong đời sống tình cảm của bạn (là bạn hoặc người ảnh hưởng); yêu bằng sự tự tin, giữ lửa bằng đời sống riêng phong phú.",cv:"Lãnh đạo bằng truyền cảm hứng, networking rộng; hợp nghề đối ngoại, thương hiệu, đào tạo. Sự tự tin của bạn đang là tài sản của cả nhóm.",tc:"Quản tiền tự tin, dám chi cho hình ảnh và mối quan hệ — miễn có tính toán; nguồn thu từ cộng đồng, khách quen nở rộ.",sk:"Sức sống tốt; chú ý cân bằng nội tiết và tim mạch khi 'cháy' quá nhiều cho người khác."},
{ty:"Người đàn ông bản lĩnh, nhìn xa — bạn đời/đối tượng có tố chất dẫn dắt; trong quan hệ, hào phóng tầm nhìn nhưng đừng áp đặt lộ trình lên người kia.",cv:"Tư duy chủ doanh nghiệp: nhìn 3–5 năm, giao việc, giữ lửa đội ngũ; thời điểm nhận vai đầu tàu hoặc gặp được người đỡ đầu tầm cỡ.",tc:"Đầu tư theo tầm nhìn dài với khẩu vị rủi ro có kiểm soát; cơ hội từ người dẫn dắt uy tín — thẩm định rồi hãy theo.",sk:"Đừng để vai trò 'trụ cột' nuốt mất giờ nghỉ; huyết áp, dạ dày là điểm yếu của người gánh việc lớn."},
/* ----- CỐC (Cups) ----- */
{ty:"Trái tim mở cửa: rung động mới, lời tỏ tình, hàn gắn, tin vui thai — dòng cảm xúc tinh khôi nhất; đón nhận đừng phân tích quá.",cv:"Khởi đầu thuận về quan hệ nơi làm việc: đồng nghiệp quý, đối tác thiện chí; nghề sáng tạo, chăm sóc, nghệ thuật vào mùa.",tc:"Tiền đến từ quan hệ tốt (giới thiệu, quà, hợp tác thiện chí); cho đi đúng chỗ đang mở nguồn về sau.",sk:"Chữa bằng cảm xúc: kết nối, nghệ thuật, nước (bơi, tắm khoáng); uống đủ nước — nghĩa đen."},
{ty:"Hai trái tim cùng nhịp: hẹn hò tiến triển, cầu hôn, làm hoà; quan hệ cân bằng cho–nhận hiếm có — vun vào.",cv:"Đối tác ăn ý xuất hiện; hợp đồng song phương công bằng. Làm việc cặp đôi hiệu quả hơn làm đội đông lúc này.",tc:"Chia sẻ tài chính minh bạch trong quan hệ đối tác/đôi lứa; khoản chung nên có thoả thuận rõ ngay từ đầu tốt đẹp này.",sk:"Người đồng hành giúp bạn giữ nếp lành; khám sức khoẻ đôi trước hôn nhân là ý hay đúng thời điểm."},
{ty:"Niềm vui được chia với hội bạn; đám cưới, họp mặt se duyên. Lưu ý ranh giới: bạn thân và người yêu cần khoảng riêng rõ ràng.",cv:"Thành công của cả đội — ăn mừng rồi ghi công đúng người; sự kiện, tiệc công ty mở ra quan hệ tốt.",tc:"Hùn vốn nhóm bạn có thể vui và lời — nếu giấy tờ rõ; chi tiêu tụ tập tăng, đặt hạn mức vui vẻ.",sk:"Niềm vui xã giao bồi bổ tinh thần; chừng mực rượu bia tiệc tùng kẻo vui quá hoá hại."},
{ty:"Bạn đang thờ ơ với người thật lòng vì mải nhìn thứ ngoài tầm; hoặc chán trong quan hệ vì nhàm. Món quà trước mặt sắp bị rút lại — nhìn kỹ trước khi từ chối.",cv:"Chán việc, ngồi mơ việc khác trong khi cơ hội thật đang chìa ra; đánh giá lại lời đề nghị hiện có trước khi mơ xa.",tc:"Thờ ơ với khoản sinh lời chậm mà chắc; đôi khi 'nhàm chán' chính là dấu hiệu của khoản đầu tư tốt.",sk:"Uể oải, mất động lực — đổi mới cách tập, cách ăn cho có hứng; kiểm tra thiếu chất và trầm cảm nhẹ nếu kéo dài."},
{ty:"Đang khóc cho phần đã mất mà quên phần còn lại vẫn đứng sau lưng: người còn thương, gia đình còn đó; tiếc thương có kỳ hạn rồi quay lại với người còn ở lại.",cv:"Dự án đổ không có nghĩa sự nghiệp đổ; gom bài học từ 'ba cốc đổ', dựng lại từ 'hai cốc còn'. Đừng nộp đơn nghỉ trong lúc buồn.",tc:"Khoản lỗ đã xảy ra — đau nhưng chưa mất hết; kiểm kê phần còn lại một cách lạnh tĩnh trước khi quyết gì thêm.",sk:"Nỗi buồn ảnh hưởng dạ dày, giấc ngủ; cho phép mình buồn có thời hạn, rồi vận động nhẹ để máu chảy lại."},
{ty:"Người cũ quay về, hoặc tình mới mang cảm giác thân quen như đã gặp từ kiếp nào; những cử chỉ ngọt kiểu 'ngày xưa' hâm nóng quan hệ.",cv:"Cơ hội đến từ mối quan hệ cũ: đồng nghiệp xưa, khách cũ, trường cũ; đừng ngại nối lại liên lạc tử tế.",tc:"Khoản cũ quay về (nợ được trả, quà tặng, thừa hưởng); nguồn thu từ sản phẩm hoài niệm, đồ xưa cũng có lộc.",sk:"Liệu pháp đơn giản ngày xưa hiệu nghiệm (vườn tược, món quê, chơi với trẻ); chữa lành đứa trẻ bên trong là gốc rễ."},
{ty:"Nhiều lựa chọn tình cảm nhưng toàn sương khói: người này hay ho trên mạng, người kia đẹp trong tưởng tượng; chọn bằng tiêu chí thật, gặp mặt thật.",cv:"Nhiều hướng đi làm bạn tê liệt; liệt kê, chấm điểm theo tiêu chí, chọn MỘT. Cảnh giác lời mời 'việc nhẹ lương cao'.",tc:"Rừng cơ hội ảo: coin lạ, dự án vẽ, lãi suất trên trời; nguyên tắc thép — cái gì đẹp hơn thực tế thường không thực.",sk:"Đừng loạn theo trăm mẹo sức khoẻ trên mạng; một phác đồ khoa học theo đến cùng hơn mười mẹo bỏ dở."},
{ty:"Rời bỏ một quan hệ bề ngoài ổn nhưng bên trong cạn — không phải vì hết thương mà vì hết lớn được cùng nhau; đi tìm chiều sâu mình thật sự cần.",cv:"Từ bỏ vị trí ổn định để tìm ý nghĩa: nghỉ việc chuyển hướng, học lại từ đầu; kế hoạch rút lui tử tế, bàn giao đàng hoàng.",tc:"Rút khỏi khoản đầu tư 'ổn mà mòn' để chuyển vốn sang giá trị dài hạn hơn; chấp nhận chi phí chuyển đổi.",sk:"Cần một kỳ 'rút lui dưỡng thương': nghỉ phép dài, retreat, đổi môi trường; sức khoẻ tinh thần đang xin được ưu tiên."},
{ty:"Giai đoạn mãn nguyện: được yêu đúng cách mình muốn; điều ước tình cảm thành thật. Tận hưởng, và đừng quên người kia cũng có điều ước của họ.",cv:"Thành quả ngọt: mục tiêu đạt, được hưởng đãi ngộ xứng; tự thưởng hợp lý rồi đặt điều ước nghề nghiệp kế tiếp.",tc:"Dư dả để hưởng: bữa ngon, chuyến đi, món đồ ao ước — trong ngân sách; 'lá bài điều ước' nhắc: viết rõ điều ước tài chính kế tiếp.",sk:"Thể trạng dễ chịu; cẩn thận thừa cân do hưởng thụ — ngon miệng nhưng có điểm dừng."},
{ty:"Hạnh phúc gia đình trọn vẹn: nhà cửa êm, con cái vui, hai bên nội ngoại thuận; nếu đang yêu, đây là quẻ 'về chung nhà được đấy'.",cv:"Công việc và gia đình đạt thế cân bằng hiếm có; lựa chọn nghề nghiệp lúc này nên ưu tiên phương án giữ được mái ấm.",tc:"Tài chính phục vụ tổ ấm là đúng hướng: nhà, giáo dục con, bảo hiểm gia đình; của cải có ý nghĩa khi cả nhà cùng hưởng.",sk:"Không khí gia đình hoà thuận là liều thuốc bổ cho cả nhà; nấu ăn chung, đi chơi chung — sức khoẻ tinh thần lên theo."},
{ty:"Lời tỏ tình dễ thương, tin nhắn làm quen bất ngờ, cử chỉ lãng mạn nhỏ; đón nhận với sự trong sáng, đáp lại chân thành.",cv:"Ý tưởng sáng tạo non trẻ đáng nuôi; tin tức tốt về mảng nghệ thuật, nội dung, thiết kế; trực giác nghề nghiệp đang nhạy.",tc:"Tin nhỏ vui về tiền; nguồn thu phụ từ tài lẻ sáng tạo (viết, vẽ, làm đồ thủ công) nên thử.",sk:"Cảm xúc dễ dao động như nước; viết nhật ký, nghệ thuật trị liệu hợp; để ý da và dị ứng nhẹ."},
{ty:"Người mang trái tim trên tay áo đến với bạn: lãng mạn, chiều chuộng, biết làm bạn cảm động; cho câu chuyện thời gian để xem sự lãng mạn có đi cùng trách nhiệm.",cv:"Lời mời hợp tác thiện chí, môi trường trọng cảm xúc – thẩm mỹ; theo đuổi mục tiêu bằng sự tinh tế thay vì đối đầu.",tc:"Lời đề nghị tài chính nghe rất đẹp — kiểm tra tính khả thi; đầu tư vào cái đẹp (nghệ thuật, thương hiệu) có lộc nếu thẩm định kỹ.",sk:"Nghe cơ thể như nghe người yêu: dịu dàng, đều đặn; spa, massage, nghỉ dưỡng nhẹ đúng lúc."},
{ty:"Người phụ nữ thấu cảm sâu — yêu bằng trực giác, hiểu bạn trước khi bạn nói; bài học là giữ lòng trắc ẩn mà không đánh mất ranh giới bản thân.",cv:"Nghề chăm sóc con người (tư vấn, y tế, nhân sự, giáo dục) vượng; trong nhóm, bạn là người giữ nhiệt cảm xúc — đừng ôm cảm xúc của tất cả.",tc:"Trực giác tài chính đang nhạy — nhưng vẫn đối chiếu số liệu; chi cho gia đình, người thân có kế hoạch.",sk:"Nhạy cảm với năng lượng người xung quanh — cần thời gian một mình để 'xả'; chú ý tuần hoàn, bạch huyết, giữ ấm."},
{ty:"Người đàn ông điềm đạm sâu sắc — yêu kín đáo mà bền; trong sóng gió quan hệ, người giữ được bình tĩnh sẽ giữ được con thuyền.",cv:"Lãnh đạo bằng trí tuệ cảm xúc: lắng nghe, điều tiết xung đột, quyết định không nóng vội; vị trí quản lý con người hợp bạn.",tc:"Quyết định tiền bạc bằng cái đầu lạnh giữa thị trường cảm xúc; là chỗ dựa tài chính cho người khác nhưng đừng quên quỹ riêng.",sk:"Đè nén cảm xúc lâu sinh bệnh (huyết áp, dạ dày); tìm kênh xả lành: trò chuyện sâu, bơi lội, thiền."},
/* ----- KIẾM (Swords) ----- */
{ty:"Sự thật cần được nói ra trong quan hệ — một cuộc nói chuyện thẳng có thể đau nhưng gỡ được nút thắt lâu ngày; yêu trong rõ ràng.",cv:"Đột phá tư duy: ý tưởng sắc bén, quyết định dứt khoát, thắng trong tranh luận/đàm phán; văn bản, hợp đồng soạn lúc này chặt chẽ.",tc:"Nhìn thấu bản chất một thương vụ; quyết định tài chính lý trí, cắt cảm tính. Giấy tờ pháp lý tiền bạc nên làm ngay khi đầu óc đang tỉnh.",sk:"Chẩn đoán chính xác, phẫu thuật/can thiệp (nếu cần) thuận lợi; đầu óc minh mẫn — giữ bằng ngủ đủ."},
{ty:"Bịt mắt trước vấn đề không làm nó biến mất: hai người đang né cuộc nói chuyện cần thiết; ai đó phải gỡ băng che mắt trước — có thể là bạn.",cv:"Bế tắc giữa hai phương án vì thiếu dữ kiện; đi tìm thông tin còn thiếu thay vì ngồi cân mãi. Trì hoãn quyết định cũng là một quyết định — thường là tệ nhất.",tc:"Đứng giữa hai lựa chọn tài chính; đừng 'đóng băng' — chia nhỏ thử nghiệm hoặc hẹn ngày quyết cụ thể.",sk:"Căng thẳng do dồn nén không nói; đau đầu, mỏi mắt tăng — giảm màn hình, tập thở, nói ra được thì nhẹ nửa bệnh."},
{ty:"Trái tim chịu vết cắt: sự thật đau, lời nói tổn thương, phản bội hoặc chia ly; đau này cần được khóc cho trọn rồi mới lành — đừng nhốt nó.",cv:"Lời phê bình gắt, xung đột lời nói, tin gây sốc nơi làm việc; tách sự việc khỏi cảm xúc, đợi bớt đau mới trả lời email quan trọng.",tc:"Mất mát tài chính do tin sai người hoặc tin buồn về khoản chung; ghi lại bài học bằng văn bản để lần sau có 'luật' của mình.",sk:"Tim và tinh thần liên thông — buồn quá hại tim; khám nếu đau ngực, hồi hộp; chia sẻ với người tin cậy là thuốc."},
{ty:"Quan hệ cần một kỳ nghỉ ngắn — không phải chia tay mà là lùi lại để cả hai thở; hẹn ngày quay lại nói chuyện đàng hoàng.",cv:"Nghỉ ngơi chủ động sau chặng căng: xin nghỉ phép, tạm rời dự án; hiệu suất sẽ trở lại cùng sức lực. Chưa vội quyết việc lớn khi đang mệt.",tc:"Tạm ngừng giao dịch, để tiền 'nằm nghỉ' nơi an toàn; thời gian này dùng để học và quan sát thị trường.",sk:"Toa thuốc chính là NGHỈ: ngủ bù, tĩnh dưỡng, giảm kích thích; cơ thể đang tự sửa chữa — đừng cắt ngang."},
{ty:"Cuộc cãi mà bạn 'thắng' nhưng mất người; hỏi mình: muốn đúng hay muốn còn nhau? Có lúc rút lui khỏi trận cãi là thắng thật sự.",cv:"Không khí ăn thua, chơi xấu, giành công; thắng bằng mọi giá sẽ trả bằng quan hệ. Chọn trận đáng đánh, rời trận chỉ có mùi thuốc súng.",tc:"Cẩn thận thắng kiện/thắng kèo mà lỗ phí tổn; thoả thuận đôi bên cùng chấp nhận được thường rẻ hơn 'chiến thắng'.",sk:"Hậu quả của hơn thua: mất ngủ, nghiến răng, dạ dày; buông bớt một trận chiến là bớt một đơn thuốc."},
{ty:"Hai người cùng rời vùng nước dữ: chuyển giai đoạn êm hơn sau khủng hoảng, có thể là chuyển chỗ ở để làm mới; vết cũ lành dần theo hải trình.",cv:"Chuyển việc, chuyển bộ phận, chuyển thành phố — sang vùng nước yên hơn; quá trình chuyển cần người chèo lái lặng lẽ, chính là bạn.",tc:"Chuyển tài sản sang cấu trúc an toàn hơn; chi phí di chuyển/chuyển đổi là khoản đáng chi lúc này.",sk:"Hồi phục theo hướng rời xa nguồn stress; thay đổi môi trường sống/không khí giúp bệnh mạn tính dễ chịu hơn."},
{ty:"Có sự không trung thực quanh quan hệ: giấu giếm, ngoại tình tinh thần, hoặc chính bạn đang né sự thật; kiểm tra lòng mình trước, rồi đối thoại thẳng.",cv:"Ai đó hành động sau lưng: giành ý tưởng, đi đêm; giữ bằng chứng công việc, cẩn trọng chia sẻ kế hoạch. Nếu phải 'đi một mình', làm cho đàng hoàng.",tc:"Rủi ro gian lận, khuất tất giấy tờ; kiểm tra sao kê, hợp đồng, chữ ký. Không cho mượn danh nghĩa, giấy tờ tuỳ thân.",sk:"Đừng giấu bác sĩ triệu chứng, đừng tự ý bỏ thuốc; bệnh giấu diếm là bệnh khó chữa nhất."},
{ty:"Cảm giác 'không thoát được' mối quan hệ này là ảo giác do niềm tin tự trói; bạn có nhiều lựa chọn hơn mình nghĩ — bước đầu tiên là thừa nhận điều đó.",cv:"Tự nhốt trong 'không thể': không thể xin tăng lương, không thể đổi việc; thử liệt kê rào cản thật vs rào cản tưởng — đa số là tưởng.",tc:"Tư duy khan hiếm đang trói quyết định; tìm người cố vấn giúp nhìn lối ra tài chính mà bạn không thấy vì đứng quá gần.",sk:"Lo âu tạo vòng xoắn triệu chứng; liệu pháp nhận thức – hành vi, thiền, và vận động là kéo cắt dây trói hiệu quả."},
{ty:"Nỗi lo đêm khuya phóng đại chuyện tình cảm gấp mười; đừng diễn tập kịch bản chia tay lúc 2 giờ sáng. Sáng mai, nói chuyện thật thay vì độc thoại trong đầu.",cv:"Áp lực công việc theo vào giấc ngủ; tách 'việc cần làm' ra giấy trước khi ngủ. Sai lầm bạn sợ thường chưa xảy ra và ít ai để ý như bạn tưởng.",tc:"Mất ngủ vì tiền là tín hiệu phải tái cấu trúc: quỹ khẩn cấp, giãn nợ, bảo hiểm; nỗi sợ có tên sẽ bớt đáng sợ — viết hết ra.",sk:"Mất ngủ, ác mộng, lo âu — ưu tiên chữa ngay: vệ sinh giấc ngủ, hạn caffeine, gặp chuyên gia nếu quá 2 tuần."},
{ty:"Chạm đáy một chuyện tình — sự kết thúc rõ ràng đến mức không thể tự dối nữa; và chính vì thế, hôm nay là ngày đầu của hồi phục. Bình minh đã cài sẵn trong lá bài này.",cv:"Dự án/vai trò chấm dứt hẳn, có thể kèm cảm giác bị 'đâm sau lưng'; khép hồ sơ, giữ bài học, KHÔNG mang oán sang chương mới.",tc:"Khoản đầu tư về đáy, chấp nhận hiện thực để được giải phóng; từ đáy này, mọi bước là bước lên.",sk:"Kiệt quệ chạm giới hạn — buộc phải nghỉ hẳn một nhịp; hồi phục sau đó thường bền vì bạn đã 'sợ đúng mức'."},
{ty:"Người mới tò mò về bạn, hỏi han dò ý; hoặc chính bạn đang 'điều tra' đối tượng. Tìm hiểu là tốt — nghi ngờ bệnh lý là hỏng; kiểm chứng rồi tin.",cv:"Tin đồn công sở, lời nói cần cân nhắc; kiểm tra thông tin trước khi chuyển tiếp. Kỹ năng phân tích của bạn đang được việc — dùng vào dữ liệu, đừng dùng vào soi người.",tc:"Tin tài chính chưa kiểm chứng lan nhanh; đọc số liệu gốc, đừng nghe 'người ta bảo'. Cảnh giác chiêu 'tin nội bộ'.",sk:"Đọc lắm triệu chứng trên mạng sinh bệnh tưởng; một buổi khám thật đáng giá hơn trăm lượt tìm kiếm."},
{ty:"Người lao vào tim bạn như cơn lốc — mãnh liệt, nói lời sắc; hấp dẫn đấy nhưng hỏi: sau cơn lốc là bầu trời hay bãi chiến trường? Chậm một nhịp.",cv:"Xông trận: deadline nước rút, đàm phán cứng, bảo vệ đề án; chuẩn bị dữ liệu như chuẩn bị vũ khí. Đừng gửi tin nhắn/email khi đang bốc hoả.",tc:"Cám dỗ all-in theo đà thị trường; tốc độ chỉ tốt khi đúng hướng — đặt điểm dừng lỗ trước khi vào lệnh.",sk:"Căng như dây đàn: nguy cơ tăng huyết áp, đau nửa đầu; xả áp bằng vận động cường độ cao có kiểm soát."},
{ty:"Yêu bằng mắt mở: nhìn rõ người kia cả ưu lẫn khuyết mà vẫn chọn — đó là kiểu yêu của lá này; nói chuyện thẳng, không bóng gió, không thao túng.",cv:"Phong cách chuyên nghiệp sắc sảo: phản biện chuẩn, ranh giới rõ, không dây thị phi; hợp vai cố vấn, thẩm định, pháp chế, biên tập.",tc:"Quyết định tiền độc lập, không theo đám đông; đọc kỹ mọi điều khoản — bạn chính là người phát hiện ra dòng chữ nhỏ.",sk:"Đầu óc tỉnh nhưng dễ khô khan cảm xúc; cân bằng bằng kết nối ấm; chú ý vai gáy, khớp tay do làm việc trí óc dài."},
{ty:"Người lý trí mạnh — yêu bằng nguyên tắc và trách nhiệm hơn lời ngọt; nếu đó là bạn: nhớ rằng trái tim không phải phiên toà, người thương cần được nghe bằng lòng trắc ẩn.",cv:"Quyền uy chuyên môn: ra phán quyết, đặt tiêu chuẩn, cầm cân công việc; thời điểm làm việc với luật sư, chuyên gia đầu ngành thuận lợi.",tc:"Chiến lược tài chính chặt chẽ dựa trên luật và số liệu; tư vấn chuyên nghiệp (thuế, luật, đầu tư) đáng đồng tiền lúc này.",sk:"Kỷ luật sức khoẻ sắt — tốt, nhưng đừng máy móc đến vô cảm với tín hiệu cơ thể; não cần chơi, không chỉ cần đúng."},
/* ----- TIỀN (Pentacles) ----- */
{ty:"Tình cảm bén rễ vào thực tế: hẹn hò đàng hoàng, kế hoạch cụ thể, người thật việc thật; món quà vật chất nhỏ mang thông điệp lớn.",cv:"Cơ hội việc làm/hợp đồng mới chắc tay; lời mời có số má cụ thể. Nhận rồi xây từ móng — cơ hội này đáng đầu tư dài.",tc:"Hạt giống tài lộc: khoản đầu tư mới nền tảng tốt, lương thưởng khởi sắc; mở tài khoản tiết kiệm/đầu tư định kỳ ngay hôm nay là hợp thời.",sk:"Khởi đầu chu trình chăm sóc thân thể bài bản: khám tổng quát, kế hoạch dinh dưỡng; nền tảng thể lực đang thuận để xây."},
{ty:"Tung hứng giữa tình yêu và trăm việc khác; người kia cần thấy mình trong 'lịch' của bạn chứ không chỉ trong lời hứa. Linh hoạt nhưng đừng lỏng tay với điều quan trọng.",cv:"Đa nhiệm khéo léo, ưu tiên thay đổi liên tục; dùng công cụ quản lý việc thay vì trí nhớ. Nếu mọi thứ đều gấp — thì chưa biết cái gì quan trọng.",tc:"Cân đối dòng tiền vào–ra khéo léo; giai đoạn thu chi bấp bênh nên có 2 tài khoản: cứng cho cố định, mềm cho linh hoạt.",sk:"Nhịp sống nhấp nhô — giữ neo bằng giấc ngủ cố định; say tàu xe, rối tiêu hoá do sinh hoạt thất thường là điểm cần canh."},
{ty:"Xây quan hệ như xây nhà thờ: mỗi người một tay nghề, cùng bản vẽ chung; gia đình hai bên 'nghiệm thu' và quý bạn — cứ chân thành mà xây.",cv:"Tay nghề được công nhận, dự án nhóm ăn ý; nêu rõ đóng góp của mình một cách chuyên nghiệp. Học nghề với người giỏi lúc này tiến rất nhanh.",tc:"Thu nhập tăng nhờ tay nghề được đánh giá đúng; đầu tư vào chứng chỉ, công cụ hành nghề sinh lời chắc chắn nhất.",sk:"Kết hợp chuyên gia (bác sĩ, HLV, dinh dưỡng) — đội ngũ đúng giúp mục tiêu sức khoẻ nhanh gấp ba tự mò."},
{ty:"Giữ người quá chặt vì sợ mất — sự kiểm soát đang bóp nghẹt tình cảm; nới tay ra, tình yêu không phải tài sản để khoá két.",cv:"Giữ ghế, giữ thông tin, ngại chia sẻ vì sợ mất vị trí; sự an toàn kiểu này chặn đường thăng tiến. Chia bài mới được chia bài lại.",tc:"Tiết kiệm tốt nhưng đang thành khư khư: tiền nằm chết không sinh lời, chi cần thiết cũng tiếc; giữ 3–6 tháng phòng thân, phần còn lại cho tiền đi làm việc.",sk:"Căng cứng do 'giữ': bụng, hàm, vai; các bài thả lỏng, kéo giãn, xoa bóp giúp cả thân lẫn tâm học cách buông."},
{ty:"Cảm giác bị bỏ rơi ngoài rét trong khi 'nhà thờ' sáng đèn ngay cạnh: đừng vì tự ái mà không gõ cửa; nói 'em cần anh/anh cần em' không làm ai nhỏ đi.",cv:"Giai đoạn khó khăn việc làm; đừng giấu — mạng lưới quan hệ chính là cánh cửa sáng đèn ấy: cựu đồng nghiệp, thầy cũ đều có thể chìa tay.",tc:"Túng thiếu tạm thời; rà trợ cấp, chính sách, quỹ hỗ trợ mà bạn đủ điều kiện nhưng chưa hỏi. Tránh vay nóng — cửa đó dẫn xuống chứ không dẫn ra.",sk:"Sức đề kháng xuống khi thiếu thốn – lo âu; giữ ấm, ăn đủ chất giá rẻ (trứng, đậu, rau); y tế cộng đồng, BHYT — dùng quyền lợi mình có."},
{ty:"Cho–nhận trong tình cảm cần công bằng cả hai chiều; nếu bạn luôn là người cho: học nhận. Nếu luôn nhận: học đáp. Quà và sự giúp đỡ chân thành đang đến.",cv:"Được người trên nâng đỡ, hoặc đến lượt bạn dìu người mới; sự hào phóng chuyên môn tạo uy tín bền hơn mọi PR.",tc:"Tiền vào từ quà tặng, thưởng, hỗ trợ; cho vay/cho tặng trong khả năng và minh bạch. Cân nhắc trích quỹ từ thiện định kỳ — của cho đúng là của để.",sk:"Cho đi sức khoẻ cũng là nhận: hiến máu (nếu đủ chuẩn), chăm người bệnh; và ngược lại — dám nhờ người chăm khi mình ốm."},
{ty:"Tình cảm như cây đã trồng — đủ nước đủ nắng rồi, giờ là kiên nhẫn; đánh giá giữa kỳ: mối quan hệ này có đang lớn không? Nếu có, chờ tiếp là xứng đáng.",cv:"Điểm dừng chiến lược: đo lại hiệu quả sau chặng dài cày cuốc; thứ gì hiệu quả — tưới thêm, thứ gì èo uột — nhổ. Đừng nhầm bận rộn với tiến bộ.",tc:"Khoản đầu tư cần thời gian ủ; xem lại danh mục định kỳ nhưng đừng nhổ cây lên xem rễ mỗi tuần. Lãi kép cần bạn để yên cho nó làm việc.",sk:"Kết quả rèn luyện đến chậm hơn mong đợi nhưng đang đến; đo tiến bộ theo tháng, không theo ngày; kiên trì phác đồ."},
{ty:"Tình yêu trưởng thành bằng những việc nhỏ làm đi làm lại: đón đưa, nấu bữa, lắng nghe; lãng mạn của lá này là sự tận tâm — và nó bền hơn hoa hồng.",cv:"Mài nghề đến độ tinh: học sâu, luyện chi tiết, làm mẫu chuẩn; giai đoạn 'thợ cả' đang gần — sản phẩm của bạn bắt đầu có chữ ký riêng.",tc:"Thu nhập tăng theo tay nghề; đầu tư đều đặn kiểu 'mỗi kỳ một viên gạch' (DCA) hợp với lúc này hơn đánh quả lớn.",sk:"Thói quen nhỏ lặp lại làm nên sức khoẻ lớn: 15 phút/ngày đều đặn thắng 3 giờ/tuần ngẫu hứng; kiên trì vật lý trị liệu nếu đang tập phục hồi."},
{ty:"Bạn không cần ai để 'đủ' — và chính sự tự tại đó đang hấp dẫn; trong quan hệ: giữ khu vườn riêng (bạn bè, sở thích, tài chính) làm tình yêu thêm sang.",cv:"Vị thế chuyên gia độc lập: làm chủ lịch, chọn dự án, giá của bạn do bạn đặt; thành quả này từ kỷ luật nhiều năm — hưởng nó đàng hoàng.",tc:"Độc lập tài chính trong tầm với: thu nhập thụ động bắt đầu gánh chi phí; tự thưởng có gu, trong kế hoạch — sang trọng khác hoang phí.",sk:"Tự chủ nhịp sống giúp sức khoẻ nở hoa; làm đẹp, chăm da, không gian sống xanh — đầu tư cho chất lượng sống là đầu tư thật."},
{ty:"Tình yêu tính bằng thế hệ: chuyện ra mắt, cưới xin, tài sản chung, con cái — gia đình hai bên đóng vai trò lớn; xây 'gia tộc' cần cả tình lẫn cấu trúc rõ ràng.",cv:"Làm việc trong/với doanh nghiệp gia đình, tổ chức lâu đời; xây hệ thống để việc chạy không cần bạn — đó là đẳng cấp kế thừa được.",tc:"Của cải dài hạn: bất động sản, thừa kế, bảo hiểm, di chúc; giấy tờ tài sản gia đình nên rõ ràng sớm — minh bạch là giữ hoà khí.",sk:"Chú ý bệnh có yếu tố di truyền — tầm soát theo tiền sử gia đình; nếp sống lành của cả nhà là di sản sức khoẻ cho con cháu."},
{ty:"Người thật thà, ham học đang để ý bạn — hoặc tình cảm hiện tại cần được 'học' một cách nghiêm túc: học cách người kia muốn được yêu.",cv:"Tin tốt về học hành, khoá học, việc mới cho người mới; thái độ học việc chăm chỉ đang được để mắt — cứ bền bỉ, cơ hội thật đến từ đây.",tc:"Bắt đầu học tài chính bài bản: sách, khoá học, thực hành sổ chi tiêu; khoản 'học phí' nhỏ lúc này là khoản đầu tư lời nhất đời.",sk:"Học kiến thức sức khoẻ từ nguồn chuẩn; bắt đầu chương trình tập có giáo án; kiểm tra mắt, tư thế ngồi học/làm."},
{ty:"Người chậm mà chắc: không lãng mạn hoa mỹ nhưng đến đúng giờ, làm đúng hứa; nếu bạn cần sự ổn định — đây là 'nhân sự' đáng giữ; nếu bạn cần bay bổng — nói rõ nhu cầu.",cv:"Cày bền, quy trình chuẩn, không bỏ sót chi tiết; dự án dài hơi cần đúng người như bạn. Cẩn thận sức ì: thỉnh thoảng phải ngẩng lên xem đường có đổi không.",tc:"Tích sản kiểu nông dân: đều đặn, không đòn bẩy, không nghe sóng; chậm ở đây là một tính từ đắt giá — hãy tự hào về nó.",sk:"Bền bỉ là gen của bạn — duy trì môn sức bền (đi bộ, đạp xe); coi chừng cứng khớp, trì trệ chuyển hoá do ngồi lâu — đứng dậy mỗi giờ."},
{ty:"Người phụ nữ vừa lo được kinh tế vừa ấm được mái nhà — nếu là bạn: đừng quên tự chăm mình giữa lúc chăm cả thế giới; món quà thiết thực là ngôn ngữ yêu của lá này.",cv:"Quản lý thực tế, chu toàn, giỏi cả chuyên môn lẫn hậu cần; môi trường ổn định – sản phẩm thật (thực phẩm, nhà đất, giáo dục, y tế) hợp.",tc:"Tay hòm chìa khoá xuất sắc: chi tiêu khôn, đầu tư chắc, nhà cửa vén khéo; nguồn thu từ kinh doanh tại gia, đất vườn thuận.",sk:"Cho mình vào danh sách ưu tiên chăm sóc — khám định kỳ, dinh dưỡng cho chính mình; đôi vai gánh gia đình cần được xoa bóp thật sự."},
{ty:"Người đàn ông vững như núi về vật chất, yêu bằng sự bảo đảm: 'ở bên tôi, em/anh không phải lo'; giá trị thật — miễn đừng biến chu cấp thành quyền kiểm soát.",cv:"Đỉnh chuỗi sự nghiệp thực tế: quản lý tài sản lớn, chốt thương vụ, đỡ đầu người trẻ; chạm việc gì ra giá trị việc đó — chọn việc xứng tầm mà chạm.",tc:"Tài sản đạt độ chín: đa dạng, sinh lời đều; giai đoạn 'tiền làm việc cho mình' — tập trung quản trị rủi ro và kế hoạch truyền lại.",sk:"Cảnh giác bệnh của người thành đạt: mỡ máu, gout, tiểu đường, tim mạch — tiệc tùng có chiến lược; sức khoẻ là tài sản gốc, đừng để nó thành chi phí."}
];

/* LEN_EXT: cùng thứ tự LENORMAND (1-36). ty=tình yêu, cv=công việc, tc=tiền bạc */
const LEN_EXT = [
{ty:"Người mới xuất hiện mang theo rung động; tin nhắn/lời tỏ ý đang trên đường đến — hồi âm nhanh kẻo nguội.",cv:"Tin tức công việc sắp về: kết quả phỏng vấn, phản hồi đề án; mọi thứ bắt đầu chuyển động sau thời gian im ắng.",tc:"Tin về tiền: thông báo chuyển khoản, kết quả xét duyệt; giao dịch cần tốc độ thì đây là lúc."},
{ty:"May mắn nhỏ trong tình cảm: buổi gặp tình cờ dễ thương, cơ hội làm quen thoáng qua — nắm ngay trong 1-2 ngày.",cv:"Cơ hội ngắn hạn: việc gấp lương tốt, dự án chen ngang có lợi; cửa sổ cơ hội hẹp, quyết nhanh.",tc:"Lộc nhỏ bất ngờ: trúng thưởng nhỏ, giảm giá sâu, khoản hoàn tiền; vui nhưng đừng xem là nguồn thu."},
{ty:"Tình yêu xa, người từ phương xa, hoặc chuyến đi chung sẽ đổi chất mối quan hệ; nhớ nhung là gia vị — chủ động rút ngắn khoảng cách.",cv:"Công tác xa, khách hàng/đối tác nước ngoài, cơ hội xuất ngoại; ngành logistics, du lịch, ngoại thương thuận.",tc:"Tiền từ xa về: kiều hối, thương mại điện tử xuyên biên, đầu tư thị trường ngoài; cân nhắc tỷ giá, phí chuyển."},
{ty:"Chuyện tình hướng về mái ấm: ra mắt, về chung nhà, không khí gia đình quyết định nhịp tiến; người bền vững hơn người bay bổng.",cv:"Công việc ổn định, môi trường 'như ở nhà'; làm việc tại gia, kinh doanh hộ gia đình thuận; sự nghiệp xây trên nền an toàn.",tc:"Tiền gắn với nhà: mua bán, sửa sang, cho thuê bất động sản; tài sản cố định là hướng giữ tiền đúng lúc này."},
{ty:"Tình cảm lớn chậm mà rễ sâu — người đến sau cùng thường ở lại lâu nhất; sức khoẻ và gốc gác gia đình ảnh hưởng chuyện đôi lứa.",cv:"Sự nghiệp cần thời gian bén rễ: đường dài, thăng tiến chậm nhưng chắc; ngành y tế, sức khoẻ, môi trường có lộc.",tc:"Đầu tư tăng trưởng chậm – bền (cây lâu năm); tiền cho sức khoẻ là khoản không được cắt."},
{ty:"Giai đoạn mù mờ: hiểu lầm, tâm trạng thất thường, người kia 'lúc nắng lúc mưa'; đừng phán xét nhau trong sương — chờ trời quang rồi nói chuyện.",cv:"Thông tin nhiễu, định hướng công ty chưa rõ; hoãn quyết định lớn, tập trung việc trước mắt; mây rồi sẽ tan — thường trong thời gian ngắn.",tc:"Số liệu chưa rõ ràng, khoản treo lơ lửng; không xuống tiền khi chưa thấy đáy hồ; chờ 1-2 nhịp cho thông tin lộ."},
{ty:"Người thứ ba khéo léo, sự quyến rũ có toan tính, hoặc chính sự vòng vo trong giao tiếp làm quan hệ nhiễm độc; nói thẳng là thuốc giải.",cv:"Đồng nghiệp/đối tác khôn ngoan có ý đồ riêng; đường công việc phải đi vòng — kiên nhẫn với thủ tục; dùng trí tuệ, đừng dùng mưu hèn.",tc:"Cảnh giác lời mời ngọt về tiền: hoa hồng cao bất thường, mô hình phức tạp khó hiểu; đường vòng đôi khi hợp pháp nhưng đắt — đọc kỹ phí ẩn."},
{ty:"Một giai đoạn tình cảm kết thúc để lột xác: hết mặn nồng cũ, chôn cất đúng cách rồi mới có mùa mới; đừng đào mộ quá khứ lên mỗi tuần.",cv:"Dự án/vị trí đến hồi kết; giai đoạn 'ngủ đông' nghề nghiệp — nghỉ ngơi, học thêm, chờ chu kỳ mới; đóng việc cũ cho trọn vẹn.",tc:"Khoản đầu tư hết chu kỳ — tất toán; dòng tiền tạm ngưng trệ; thanh lý đồ không dùng cũng là cách 'chôn cất' sinh tiền."},
{ty:"Lời mời hẹn hò, món quà, lời khen chân thành — tình cảm được bày tỏ đẹp; đáp lễ bằng sự trân trọng, mối quan hệ nở như hoa được tưới.",cv:"Lời mời hợp tác, thư khen, cơ hội 'được tặng'; hình ảnh chuyên nghiệp của bạn đang đẹp — duy trì nó; sự kiện xã giao mang quý nhân.",tc:"Quà giá trị, thưởng nóng, ưu đãi riêng; tiền chi cho quà tặng đúng người là khoản đầu tư quan hệ khôn ngoan."},
{ty:"Cắt đứt đột ngột hoặc quyết định dứt khoát trong tình cảm; lời nói lúc nóng như lưỡi hái — một nhát là đứt, cân nhắc trước khi vung.",cv:"Quyết định gấp: cắt hợp đồng, tinh giản, chốt deal trong ngày; rủi ro tai nạn lao động/thiết bị — kiểm tra kỹ; nhanh và chuẩn thì thắng.",tc:"Cắt lỗ, cắt chi tiêu — đau nhưng gọn; cẩn thận mất mát đột ngột: khoá thẻ, sao lưu, bảo hiểm; thu hoạch nhanh khoản đã chín."},
{ty:"Cãi vã lặp lại một kịch bản — vấn đề không nằm ở chủ đề cãi mà ở cách cãi; đổi 'vũ khí' thành đối thoại có giờ nghỉ.",cv:"Tranh luận nảy lửa, sức ép lặp đi lặp lại, môi trường cạnh tranh gắt; rèn luyện — lặp lại có chủ đích — lại chính là chìa khoá thắng.",tc:"Tiền hao vì những khoản lặt vặt lặp lại (phí ngầm, đăng ký quên huỷ); rà soát các khoản trừ tự động ngay."},
{ty:"Chuyện đôi lứa được bàn tán — cả tốt lẫn xấu; hai người nói chuyện điện thoại/nhắn tin nhiều hơn gặp; hẹn gặp thật đi, lời qua lại dễ sinh lo âu vặt.",cv:"Họp hành, đàm phán, gọi điện dồn dập; tin truyền miệng ảnh hưởng việc của bạn — chủ động phát ngôn rõ; việc thường đến theo cặp: hai lời mời, hai lựa chọn.",tc:"Bàn bạc tiền bạc: thương lượng giá, chốt qua điện thoại; giấy trắng mực đen sau mỗi cuộc gọi — lời nói gió bay."},
{ty:"Tình yêu chớm nở trong trẻo, hoặc em bé sắp có mặt trong kế hoạch; quan hệ cũ được làm mới bằng sự hồn nhiên — chơi với nhau như thuở đầu.",cv:"Dự án non trẻ cần nâng niu; vai trò mới bắt đầu từ việc nhỏ; thái độ tân binh ham học là điểm cộng lớn nhất của bạn lúc này.",tc:"Khoản đầu tư mới quy mô nhỏ — gieo hạt; chi phí cho con cái/giáo dục tăng; bắt đầu thói quen tiết kiệm nhỏ mà đều."},
{ty:"Cẩn trọng người giả ngoan hoặc chính mình đang 'diễn' để được yêu; khôn khéo giữ mình là đúng — giả dối để giữ người là sai đường.",cv:"Môi trường nhiều người khôn lỏi, chính trị văn phòng; giữ việc bằng năng lực và sự tỉnh táo; nghề tự do, mưu sinh linh hoạt gặp thời.",tc:"Cảnh giác lừa khéo: hàng nhái, hợp đồng cài bẫy, 'người quen giới thiệu'; kiểm tra chéo mọi thứ liên quan tiền dù người đưa tin thân đến đâu."},
{ty:"Người che chở mạnh mẽ (hoặc mẫu người 'gấu' bảo bọc); tình cảm ấm nhưng để ý cán cân quyền lực — che chở khác kiểm soát; mẹ/người lớn ảnh hưởng chuyện đôi lứa.",cv:"Sếp lớn để mắt đến bạn — cơ hội lẫn áp lực; quan hệ với cấp trên quyết định bước tiến; cẩn thận người ghen tị sau lưng.",tc:"Khoản tiền lớn liên quan: đầu tư đậm, vay ngân hàng, hợp đồng giá trị; có người đỡ đầu tài chính; giữ mồm về thu nhập kẻo sinh đố kỵ."},
{ty:"Sau mơ hồ là hy vọng có cơ sở: quan hệ có định hướng rõ, hai người cùng nhìn về một kế hoạch; lời ước chân thành lúc này linh nghiệm — vì nó đi kèm hành động.",cv:"Định hướng dài hạn sáng rõ: lộ trình thăng tiến, kim chỉ nam nghề nghiệp; ngành công nghệ, truyền thông, sáng tạo được 'sao chiếu'.",tc:"Kế hoạch tài chính dài hạn đặt lúc này rất thuận: mục tiêu 5 năm, quỹ hưu, bảo hiểm nhân thọ; đầu tư theo xu hướng lớn thay vì sóng nhỏ."},
{ty:"Thay đổi tốt lành: chuyển giai đoạn (yêu → cưới, xa → gần), tin vui em bé, chuyển nhà để bắt đầu chương mới; điều cũ được 'nâng cấp' chứ không mất đi.",cv:"Thăng chức, chuyển vị trí tốt hơn, tái cấu trúc có lợi cho bạn; đón nhận thay đổi chủ động — con cò bay về phương ấm.",tc:"Cải thiện thu nhập, chuyển kênh đầu tư hợp lý hơn; chi phí cho chuyển nhà/chuyển việc là đáng; nâng cấp có tính toán, không đổi mới liên miên."},
{ty:"Tình bạn thành tình yêu, hoặc tình yêu bền nhờ chất bạn; người trung thành đứng cạnh bạn không ồn ào — đừng xem đó là hiển nhiên.",cv:"Đồng minh đáng tin nơi công sở; đối tác giữ lời; tuyển người: chọn trung thực trước, giỏi sau; bạn giới thiệu việc — mối này chắc.",tc:"Chung tiền với người đáng tin thì được, nhưng vẫn giấy tờ rõ; người bạn thật sẽ không phật lòng vì hợp đồng minh bạch."},
{ty:"Một người kín đáo, khó mở lòng, hoặc chuyện tình giữ khoảng cách (thầm lặng, xa cách, 'tháp ngà'); phá băng bằng kiên nhẫn — và tôn trọng ranh giới họ.",cv:"Cơ quan, tập đoàn, pháp lý, chính quyền — việc dính đến tổ chức lớn tiến triển theo trình tự; vị trí quản lý cấp cao đơn độc nhưng tầm nhìn rộng.",tc:"Tiền liên quan cơ quan/pháp lý: thuế, hồ sơ, giấy phép, kiện tụng; làm đúng thủ tục, giữ biên nhận; đầu tư dài hạn có cấu trúc pháp lý rõ."},
{ty:"Chuyện tình 'công khai': ra mắt bạn bè, đăng ảnh, sự kiện đông người là nơi gặp gỡ; nếu đang mập mờ — lá này hỏi: sao chưa công khai?",cv:"Sự kiện, hội thảo, cộng đồng nghề — networking là chìa khoá giai đoạn này; thương hiệu của bạn cần xuất hiện nơi công cộng.",tc:"Tiền từ đám đông: bán hàng số lượng, sự kiện, cộng đồng khách; chi phí giao tế tăng — có ngân sách riêng cho nó."},
{ty:"Trở ngại lớn giữa hai người: khoảng cách, gia đình ngăn, khác biệt khó dung hoà; núi không tự dời — nhưng đường vòng và thời gian thì có thật; tình đủ lớn sẽ tìm ra đèo.",cv:"Dự án đụng tường: đối thủ nặng ký, thủ tục chặn, cấp trên block; đừng húc — tìm đường vòng, người mở đường, hoặc chờ thời; sức bền thắng sức mạnh.",tc:"Khoản tiền bị chặn/đóng băng: nợ khó đòi, giải ngân chậm, tài sản kẹt thanh khoản; kiên trì thủ tục và có phương án dòng tiền thay thế."},
{ty:"Đứng giữa hai lựa chọn tình cảm — hoặc chọn người, hoặc chọn cách tiếp tục; không chọn cũng là chọn (và thường chọn phần thiệt); quyết bằng giá trị lâu dài.",cv:"Ngã rẽ nghề nghiệp thực sự: hai lời mời, rẽ ngang hay ở lại; liệt kê 3 tiêu chí quan trọng nhất đời mình rồi soi cả hai đường vào đó.",tc:"Hai phương án tài chính khác hẳn nhau; đừng đi cả hai với vốn mỏng; chọn một, toàn tâm, đặt mốc đánh giá sau 6 tháng."},
{ty:"Điều gì đó đang âm thầm gặm quan hệ: nghi ngờ vặt, tin nhắn không trả lời, thiếu chăm sóc nhỏ; vá sớm — lỗ nhỏ đắm thuyền lớn.",cv:"Hao mòn âm thầm: việc vặt ăn hết giờ làm việc sâu, tài liệu thất lạc, quy trình rò rỉ; tổng vệ sinh quy trình một lần dứt điểm.",tc:"Tiền rò không thấy: phí duy trì, đồ hỏng vặt, mất trộm nhỏ; kiểm kê — chỗ nào 'chuột ở' sẽ lộ ngay khi bạn soi đèn."},
{ty:"Trái tim nói CÓ: rung động thật, tình cảm chân thành được trao và đáp; giai đoạn đẹp để tỏ bày, cầu hôn, hàn gắn; hãy quảng đại — trái tim rộng thì đường rộng.",cv:"Làm nghề bằng đam mê thật sẽ được nhận ra; môi trường làm việc tử tế, đồng nghiệp ấm; công việc liên quan chăm sóc, cống hiến thuận.",tc:"Chi từ trái tim (giúp người, quà cho cha mẹ) — đúng và đáng; hợp tác với người mình thật sự quý; tiền không mua được điều lá này chỉ — đừng bán nó vì tiền."},
{ty:"Cam kết chính thức: cầu hôn, đăng ký, kỷ niệm; vòng tròn cũng có nghĩa lặp lại — quan hệ cũ tái hợp có thể bền nếu cả hai đã khác xưa.",cv:"Hợp đồng được ký: việc mới, gia hạn, đối tác dài hạn; đọc kỹ điều khoản ràng buộc; lời hứa nghề nghiệp lúc này phải giữ được.",tc:"Ràng buộc tài chính: vay dài hạn, hợp đồng bảo hiểm, cổ phần; cân nhắc kỹ vì khó rút giữa chừng; đã ký thì theo đến hết vòng."},
{ty:"Bí mật trong tình cảm: điều chưa kể, quá khứ chưa mở, hoặc mối quan hệ đang giữ kín; tôn trọng nhịp mở của nhau — nhưng bí mật về lòng chung thuỷ thì không được phép có.",cv:"Kiến thức là đòn bẩy: khoá học, chứng chỉ, dự án nghiên cứu; có thông tin nội bộ chưa công bố ảnh hưởng việc của bạn — kiên nhẫn chờ công khai.",tc:"Hợp đồng/số liệu chưa mở hết trang — yêu cầu minh bạch trước khi ký; đầu tư vào tri thức (sách, học) là khoản chắc lời nhất của lá này."},
{ty:"Tin nhắn định đoạt cục diện: lời tỏ tình qua thư, tin quan trọng từ người ấy; viết ra điều khó nói — lá này bảo trợ cho chữ nghĩa chân thành.",cv:"Văn bản quyết định: hợp đồng, email chính thức, quyết định bổ nhiệm; soạn kỹ từng chữ; tin bạn chờ sẽ đến dạng giấy trắng mực đen.",tc:"Giấy tờ tiền bạc: hoá đơn, sao kê, chứng từ — lưu đủ; khoản tiền gắn với một văn bản đang trên đường; ký gì đọc nấy, từng dòng."},
{ty:"Người đàn ông trong câu chuyện — anh ấy nghĩ gì, các lá xung quanh sẽ kể; nếu bạn là nam: lá này là chính bạn giữa bàn cờ hiện tại.",cv:"Một người nam giữ vai trò then chốt trong việc của bạn: sếp, đối tác, khách; hiểu động cơ của anh ta là hiểu ván bài.",tc:"Chuyện tiền liên quan một người nam cụ thể; nhìn các lá cạnh bên để biết nên hợp tác hay giữ khoảng cách."},
{ty:"Người phụ nữ trong câu chuyện — tâm ý cô ấy hiện ở các lá xung quanh; nếu bạn là nữ: lá này là chính bạn, đang đứng giữa các dòng chảy của mình.",cv:"Một người nữ then chốt: sếp nữ, đồng nghiệp, khách hàng; sự tinh tế trong ứng xử với cô ấy mở hoặc đóng cánh cửa.",tc:"Chuyện tiền liên quan một người nữ cụ thể; các lá lân cận cho biết đó là quý nhân hay phép thử."},
{ty:"Tình cảm chín chắn, bình yên kiểu 'trà chiều': người lớn tuổi hơn, hoặc giai đoạn quan hệ đằm lại sau sóng gió; sự thanh khiết và tôn trọng là nền của chặng này.",cv:"Quý nhân lớn tuổi, cố vấn dày kinh nghiệm nâng đỡ; công việc cần độ chín, uy tín, đạo đức nghề; mùa đông sự nghiệp — chậm nhưng thanh thản, hợp trau dồi.",tc:"Tài chính an nhàn kiểu ông bà: gửi tiết kiệm, trái phiếu, của để dành; hưởng thụ thanh đạm; hỏi kinh nghiệm người đi trước trước khoản lớn."},
{ty:"Mặt trời rọi vào chuyện tình: giai đoạn hạnh phúc rõ ràng, mọi hiểu lầm tan, tình yêu thành công — câu trả lời là CÓ; cứ tự tin cầu hôn, tỏ tình, tổ chức.",cv:"Thành công rực rỡ: dự án thắng, được vinh danh, năng lượng làm việc dồi dào; các việc khởi động lúc này có 'nắng' theo suốt chặng.",tc:"Tài vận vượng nhất bộ bài: lời rõ, thưởng lớn, vận may đầu tư; vẫn trích phần dự phòng — để mùa nắng nuôi được cả mùa mưa."},
{ty:"Được người ấy công nhận, danh phận rõ ràng; đời sống cảm xúc sâu sắc về đêm — những cuộc trò chuyện khuya gắn kết; vinh danh tình cảm bằng sự trân trọng công khai.",cv:"Danh tiếng lên: được nhắc tên, khen thưởng, hồ sơ đẹp; nghề liên quan cảm xúc – nghệ thuật – ban đêm thuận; giữ danh bằng thực lực kẻo trăng khuyết.",tc:"Thu nhập từ danh tiếng: thương hiệu cá nhân, nghề tự do có tên tuổi; đầu tư vào hình ảnh chuyên nghiệp sinh lời."},
{ty:"Chìa khoá tình yêu trao tay: câu trả lời chắc chắn CÓ, cánh cửa quan hệ mở, định mệnh gõ đúng cửa; điều quan trọng sắp được mở khoá — trân trọng nó.",cv:"Giải pháp xuất hiện cho bài toán lâu ngày; bạn chính là người giữ chìa (kỹ năng độc nhất, mối quan hệ đúng); thành công có tính bước ngoặt.",tc:"Mở khoá tài chính: khoản duyệt, nút thắt gỡ, cơ hội chắc chắn hiếm hoi; đây là lá 'chốt được' — nhưng vẫn đọc hợp đồng."},
{ty:"Nhiều 'cá' quanh bạn — sức hút đang cao, có thể nhiều người theo đuổi; trong quan hệ: giai đoạn dư dả cảm xúc, hào phóng với nhau; đừng bắt cá hai tay.",cv:"Kinh doanh khởi sắc, nhiều dòng việc/khách chảy về; ngành buôn bán, tài chính, nghề tự do vượng; chọn dòng lớn nhất mà theo, đừng ôm hết.",tc:"Dòng tiền dồi dào, nhiều nguồn thu; thời điểm tốt để hệ thống hoá: tách quỹ, tái đầu tư phần dư; nước lớn phải có đê — kỷ luật giữ tiền."},
{ty:"Bến đỗ: quan hệ vào giai đoạn ổn định lâu dài, đáng tin như neo; nếu đang tìm — người 'bến bờ' xứng đáng hơn người 'con sóng'; kiên định với người mình chọn.",cv:"Công việc ổn định dài hạn, hợp đồng bền, nghề gắn bó nhiều năm; kiên trì mục tiêu — neo đã cắm thì sóng không trôi; cẩn thận neo quá chặt thành trì trệ: định kỳ xem lại.",tc:"Khoản đầu tư giữ lâu, của để dành, lương hưu; nguyên tắc neo: không rút trước hạn vì sóng nhỏ; tài chính đạt thế 'gió lay không đổ'."},
{ty:"Gánh nặng hoặc bài học lớn trong tình cảm: thử thách buộc hai người trưởng thành, hoặc mối duyên có tính 'nợ' phải trả cho xong; qua được — tình sâu hơn gấp bội.",cv:"Giai đoạn nhọc nhằn có ý nghĩa: trách nhiệm nặng, việc khó ít ai gánh; đừng vác một mình mãi — chia sẻ, và nhớ: gánh này có kỳ hạn.",tc:"Nợ nần, nghĩa vụ tài chính với gia đình; trả có kế hoạch, đừng vay chỗ này đắp chỗ kia; khoản chi tâm linh, từ thiện đúng nghĩa mang lại bình an."}
];

