const BT_EXT = [
{ty:"Mái ấm đón tin vui: tỏ tình thành, hoà thuận, tiệc mừng trong nhà.",cv:"Khởi sự thuận, đồng nghiệp quý mến; tin tốt về vị trí mới.",tc:"Lộc vào nhà: thưởng, quà, khoản thu gắn với gia đình."},
{ty:"Hẹn hò tiến triển, hai lòng như một; thời điểm ngỏ lời.",cv:"Cặp đôi ăn ý trong công việc; hợp tác song phương thuận.",tc:"Thoả thuận tiền bạc win-win; chia sẻ chi phí công bằng."},
{ty:"Đừng quyết chuyện tình cảm lúc đang vui quá đà; niềm vui nhóm bạn có thể xen vào chuyện riêng.",cv:"Quyết định cần thêm cân nhắc; tin vui tập thể nhưng việc riêng phải tự lo.",tc:"Chi tiêu vui vẻ có nguy cơ lố; đặt hạn mức trước khi đi chơi."},
{ty:"Thay đổi trạng thái quan hệ; chuyến đi vì người thân; hôn sự bàn tính muộn nhưng chắc.",cv:"Điều chuyển công việc liên quan gia đình; cân bằng lại việc–nhà.",tc:"Chi phí đi lại, hiếu hỉ tăng; khoản muộn nhưng sẽ về."},
{ty:"Ghen nhẹ, dùng dằng; đừng thử lòng nhau bằng im lặng.",cv:"Do dự giữa ở và đi; thu thập thêm dữ kiện rồi hãy quyết.",tc:"Chưa rõ thì chưa xuống tiền; khất được thì khất ngắn."},
{ty:"Kỷ niệm cũ ấm lại; người xưa ghé qua — ôn chuyện được, đừng ôn lại lỗi lầm.",cv:"Mối cũ mang việc mới; kinh nghiệm cũ được trọng dụng.",tc:"Khoản cũ quay về; nguồn thu từ nghề cũ, khách cũ."},
{ty:"Người mơ mộng thất thường; lời ngọt chưa chắc lòng thật — nhìn hành động.",cv:"Kế hoạch viển vông cần xét lại; đồng nghiệp hứa nhiều làm ít.",tc:"Cẩn thận vẽ vời đầu tư; mơ ước phải kèm bảng tính."},
{ty:"Lời mời hẹn, buổi tiệc se duyên; ăn diện đẹp mà đi.",cv:"Tiệc công việc, gặp gỡ mở quan hệ; lời mời hợp tác thiện chí.",tc:"Chi giao tế sinh lộc về sau; quà mời đúng dịp là đầu tư."},
{ty:"Điều ước tình cảm thành thật — tỏ tình, cầu hôn thời điểm đẹp.",cv:"Nguyện vọng nghề nghiệp được đáp ứng; cứ mạnh dạn đề xuất.",tc:"May mắn tiền bạc; điều ước tài chính trong tầm — chốt mục tiêu."},
{ty:"Hạnh phúc viên mãn, hỉ sự lớn; lá này hoá giải điềm xấu quanh nó.",cv:"Đại cát cho sự nghiệp: thành công vượt mong đợi.",tc:"Tài lộc lớn; vận may đủ mạnh để cân các khoản rủi ro nhỏ."},
{ty:"Bạn thân thành cầu nối tình duyên; người trẻ chân thành ngỏ ý.",cv:"Cộng sự trẻ nhiệt tình; tin công việc qua bạn bè.",tc:"Tin tiền bạc tốt từ người quen; khoản nhỏ nhưng vui."},
{ty:"Người phụ nữ thuỷ chung hết lòng; trân trọng người đối tốt với mình.",cv:"Quý nhân nữ nâng đỡ; đồng nghiệp nữ đáng tin.",tc:"Người nữ giúp việc tiền nong; lời khuyên tài chính từ phụ nữ trong nhà đáng nghe."},
{ty:"Người đàn ông nhân hậu che chở; tình cảm được bảo bọc an toàn.",cv:"Sếp/cố vấn nam tốt bụng; cứ thẳng thắn trình bày nguyện vọng.",tc:"Quý nhân nam giúp vốn, giúp mối; vay mượn chính đáng được duyệt."},
{ty:"Thư/tin nhắn tình cảm kèm 'vật chất': quà, nhẫn; tình đi đôi với sự đảm bảo.",cv:"Văn bản tốt về đãi ngộ: offer, tăng lương, phụ cấp.",tc:"Tin tiền: giấy báo, khoản duyệt, nhẫn/vàng làm của."},
{ty:"Chuyện đôi lứa gắn với chuyện chi tiêu đôi; sòng phẳng để khỏi sứt mẻ.",cv:"Giao dịch nhỏ thuận; hai bên cùng có lợi.",tc:"Mua bán suôn sẻ; khoản nhỏ nhưng chắc."},
{ty:"Cãi nhau vì tiền/giấy tờ; đừng để vật chất nói thay tình cảm.",cv:"Tranh chấp hợp đồng, giấy tờ; mọi thoả thuận phải thành văn.",tc:"Rõ ràng từng đồng; khoản chung phải có chứng từ."},
{ty:"Ổn định lại sau xáo trộn; người cũ trả lại 'món nợ ân tình'.",cv:"Guồng việc vào lại quỹ đạo; khoản công sức cũ được ghi nhận.",tc:"Tiền cũ quay về: nợ được trả, hoàn ứng, hoàn thuế."},
{ty:"Tin vui bất ngờ trong tình cảm; kế hoạch chung thành công.",cv:"Thành quả đến sớm hơn dự kiến; đề án được duyệt.",tc:"Khoản thu ngoài dự tính; chốt lời đúng lúc."},
{ty:"Đừng đo tình bằng quà; cho vay người yêu là cho, đừng tính là vay.",cv:"Cẩn thận chi phí dự án vượt trần; soát ngân sách.",tc:"Cho vay khó đòi; chi tiêu cần phanh — tuần này thắt lại."},
{ty:"Lời đàm tiếu về chuyện tiền của hai người; bỏ ngoài tai, sống rõ ràng là đủ.",cv:"Thị phi quanh lương thưởng; tránh bàn lương nơi công cộng.",tc:"Tránh xa đỏ đen, hụi họ rủi ro; 'phi vụ' rỉ tai — bỏ."},
{ty:"Tình xa có tin tốt; chuyến đi ngắn cùng nhau gắn kết.",cv:"Công tác ngắn sinh lợi; khách phương xa mang việc.",tc:"Tiền về theo đường xa: đơn hàng tỉnh khác, đối tác ngoại."},
{ty:"Bất ngờ ngọt ngào: quà, lời ngỏ, cơ hội gặp gỡ mới.",cv:"Cơ hội kinh doanh/dự án mới xuất hiện đột ngột — thẩm định nhanh mà kỹ.",tc:"Lộc bất ngờ; trích một phần vào quỹ dài hạn ngay kẻo tan."},
{ty:"Đám cưới bàn chuyện của cải; tình cảm và tài sản song hành thuận.",cv:"Thành công lớn: thăng chức kèm đãi ngộ, dự án ngân sách to.",tc:"Khoản tiền lớn về; đầu tư xa (địa lý/kỳ hạn) sinh lời."},
{ty:"Người đưa tin tình cảm; chàng trai công chức, nghiêm túc chuyện giấy tờ.",cv:"Tin từ cơ quan công quyền; hồ sơ, công văn được xử lý.",tc:"Tin giấy tờ tiền bạc: hợp đồng, chứng từ, kết quả xét duyệt."},
{ty:"Người nữ sắc sảo thích giao du — vui đấy nhưng chuyện riêng nên giữ mình.",cv:"Đối tác nữ giỏi giang, quảng giao; hợp tác được việc nhưng rõ ràng điều khoản.",tc:"Buôn có bạn — người nữ mát tay dẫn mối; cảnh giác buôn chuyện lẫn vào buôn bán."},
{ty:"Người đàn ông thực dụng; tình cảm cần chứng minh bằng cam kết cụ thể.",cv:"Sếp/đối tác quyền lực về tài chính; trình bày bằng con số sẽ thuyết phục.",tc:"Người nắm hầu bao quyết định; chuẩn bị hồ sơ tài chính chỉn chu."},
{ty:"Khởi đầu tốt cho tình cảm gắn với sự nghiệp: đồng nghiệp thành người thương.",cv:"Tin mừng công việc: nhận việc, khai trương, dự án khởi động hanh thông.",tc:"Nguồn thu mới từ công việc chính; lương khởi điểm/doanh thu đầu tốt."},
{ty:"Trục trặc nhỏ được bạn bè gỡ giúp; đừng ngại nhờ người thân tín.",cv:"Vướng mắc có người gỡ; hợp tác đôi bên vượt trở ngại.",tc:"Khó khăn tạm; khoản hỗ trợ từ bạn bè đến đúng lúc."},
{ty:"Sau vài lần lỡ duyên là mối chắc chắn; hôn sự mang lại phúc lộc.",cv:"Bền chí sau vài lần thử; lần này kết quả tốt đẹp.",tc:"Kết quả tài chính tốt sau kiên trì; hôn nhân/hợp tác mang lợi ích vật chất."},
{ty:"Hẹn ước bị hoãn, người thất hứa; đừng vội trách — xác minh lý do trước.",cv:"Kế hoạch đổi giờ chót; phòng người nuốt lời — mọi thứ cần văn bản.",tc:"Khoản hẹn bị trễ; đòi khéo, có mốc thời gian mới."},
{ty:"Bạn mới dễ mến; tình cảm chớm từ tình bạn từ nơi xa.",cv:"Liên minh mới, đồng nghiệp mới hợp cạ; tin việc từ xa.",tc:"Mối làm ăn mới qua bạn giới thiệu; khởi đầu nhỏ, tiềm năng có."},
{ty:"Tình cảm được 'đầu tư' đúng: quan tâm thật, tiến triển chắc.",cv:"Kinh doanh thuận buồm; được hỗ trợ đúng lúc từ người có nghề.",tc:"Buôn bán có lãi; dòng vốn được tiếp sức."},
{ty:"May mắn nhỏ trong tình trường; cẩn thận người khác giới đem thị phi.",cv:"Vận may nghề nghiệp nhỏ; tránh dây vào rắc rối tình ái công sở.",tc:"Lộc nhỏ; đừng vì vui mà hùn vốn thiếu suy nghĩ."},
{ty:"Nôn nóng muốn 'chốt' quan hệ; tình yêu không phải thương vụ — chậm lại.",cv:"Muốn kết quả nhanh dễ làm ẩu; đọc kỹ trước khi ký cam kết.",tc:"Ham lợi nhanh là bẫy giai đoạn này; lãi cao bất thường = rủi ro cao chắc chắn."},
{ty:"Tình cảm chín chắn được gia đình ủng hộ; của hồi môn, nền tảng chung vững.",cv:"Thành tựu tích luỹ được công nhận; cơ hội từ người quen cũ có uy tín.",tc:"Di sản, tích sản dài hạn; khoản thừa hưởng hoặc chia lãi về."},
{ty:"May mắn lớn: gặp đúng người đúng thời điểm; chuyến đi chung định chuyện lâu dài.",cv:"Cú hích lớn sự nghiệp; chuyến công tác mở ra chương mới.",tc:"Tiền đến bất ngờ và đậm; hoạch định ngay kẻo 'tiền vào nhà khó'."},
{ty:"Người trẻ trung thành, nhiệt tình; tình cảm trong sáng đáng tin.",cv:"Trợ thủ đắc lực; tin tốt nghề nghiệp từ người trẻ.",tc:"Tin vui tiền bạc quy mô nhỏ; người trẻ mách cơ hội được việc."},
{ty:"Người nữ tự tin giúp chuyện tình duyên; bạn nữ giỏi làm quân sư.",cv:"Đồng nghiệp/sếp nữ giỏi giang hỗ trợ hết mình.",tc:"Người nữ mát tay chỉ đường tiền bạc; nghe nhưng vẫn tự thẩm định."},
{ty:"Người đàn ông chính trực — mẫu 'chồng/bạn đời' đáng tin cậy.",cv:"Đối tác trung thành, sếp công minh; quan hệ làm ăn dài lâu.",tc:"Quý nhân tài chính thật lòng; hợp tác vốn liếng minh bạch."},
{ty:"Quyết định hệ trọng: dứt khoát rõ ràng — mập mờ lúc này là tự hại; kết thúc để bắt đầu.",cv:"Bước ngoặt lớn cần đầu óc lạnh; văn bản pháp lý xem kỹ từng chữ.",tc:"Quyết định tiền bạc lớn: cực kỳ thận trọng, tham vấn chuyên gia."},
{ty:"Lời hai lòng, tình tay ba; đối chất thẳng thắn thay vì dò xét.",cv:"Có người nói một đằng làm một nẻo; giữ chứng cứ, bớt tâm sự.",tc:"Cẩn thận lừa gạt: kiểm tra pháp nhân, giấy tờ, người bảo lãnh."},
{ty:"Giọt nước mắt ngắn: giận hờn, xa nhau tạm; nói rõ hiểu lầm sẽ qua.",cv:"Buồn phiền vì phê bình/chia tách nhóm; ngắn thôi — làm tiếp sẽ ổn.",tc:"Hao nhỏ khiến xót; rút kinh nghiệm chứ đừng dằn vặt."},
{ty:"Mệt mỏi tình cảm — nghỉ ngơi đừng quyết định; ốm nhẹ nên hoãn hẹn quan trọng.",cv:"Sức làm việc xuống; hoãn việc lớn, giải quyết việc nhỏ.",tc:"Hoãn giao dịch lớn; sức khoẻ là khoản tiêu trước tiên."},
{ty:"Cãi vã leo thang — ai nhịn trước người đó thắng về lâu dài.",cv:"Xung đột nội bộ hao tổn; đứng ngoài cuộc đấu không phải của mình.",tc:"Tranh chấp tiền: kiện nhau là cùng thiệt — ưu tiên thương lượng."},
{ty:"Rời xa giai đoạn u ám từng bước; tình cảm hồi phục chậm mà chắc.",cv:"Thoát dần bế tắc; mỗi tuần gỡ một nút, đừng đòi gỡ cả cuộn.",tc:"Nợ giảm dần theo kế hoạch; tình hình sáng lên từng tháng."},
{ty:"Mất mát nhỏ dạy bài học chọn người; đổi cách yêu, đừng đổi niềm tin vào tình yêu.",cv:"Kế hoạch cần đổi hướng; lời khuyên chân thành từ người ngoài cuộc đáng nghe.",tc:"Hao tổn nhỏ; xem lại danh mục, chuyển hướng khoản kém."},
{ty:"Trắc trở do tác động bên ngoài; giữ lòng bền, tránh hứa mới khi chưa xong cũ.",cv:"Tin không vui về đề xuất; đừng ký cam kết mới lúc thế yếu.",tc:"Cản trở dòng tiền; phòng thủ, không mở thêm nợ."},
{ty:"Lo âu phóng đại; đêm dài lắm mộng — đừng chia tay lúc nửa đêm.",cv:"Tin xấu, trì hoãn; xử lý từng việc một, tránh quyết định trong hoảng loạn.",tc:"Kỳ khó khăn: tiền mặt là vua, cắt rủi ro, chờ qua cơn."},
{ty:"Khép một chương buồn — nước mắt cuối rồi bình minh; ai ở lại sau chặng này là người thật.",cv:"Kết thúc nặng nề của một giai đoạn; nghỉ ngơi rồi làm lại — nền cũ vẫn dùng được.",tc:"Chạm đáy chi tiêu/thu nhập; từ đây lập kế hoạch phục hồi từng quý."},
{ty:"Người trẻ tính toán trong tình cảm; thử lòng bằng thời gian, đừng bằng của cải.",cv:"Cẩn thận người dò la, mách lẻo; tin tức nghe được phải kiểm chứng.",tc:"Đề phòng mưu vặt về tiền; khoá thông tin tài khoản, không đưa mật khẩu."},
{ty:"Người nữ lạnh lùng hoặc đố kỵ xen vào; giữ phép lịch sự, không đôi co.",cv:"Cấp trên/đối tác nữ khắt khe; làm việc chuẩn chỉ, nói ít làm nhiều.",tc:"Cẩn thận người giữ tiền khó tính; minh bạch để khỏi bị bắt bẻ."},
{ty:"Người đàn ông quyền lực cản trở hoặc ghen; tránh đối đầu, dùng lý lẽ và luật.",cv:"Đối thủ nặng ký, sếp nghiêm khắc; nâng chuẩn công việc lên mức không thể chê.",tc:"Áp lực từ chủ nợ/cơ quan; xử lý bằng giấy tờ đầy đủ, đúng luật, đúng hẹn."}
];

/* KD_EXT: quẻ 1-64. tf = Thoán từ (dịch nghĩa lời kinh), ty/cv/tc/sk = luận theo lĩnh vực */
const KD_EXT = {
1:{tf:"«Nguyên, hanh, lợi, trinh» — Khởi đầu lớn lao, hanh thông, thuận lợi, bền vững nếu giữ chính đạo.",ty:"Tình cảm chủ động và quang minh; nam tính chủ đạo — người chủ động cầu hôn, tỏ tình thắng lợi; kỵ áp đặt.",cv:"Đại cát cho việc lớn: khởi nghiệp, nhậm chức, dẫn dắt; hãy như rồng bay — nhưng nhớ 'kháng long hữu hối': lên đỉnh chớ kiêu.",tc:"Tài vận mạnh, hợp đầu tư chính đạo quy mô lớn; tiền kiếm bằng thực lực bền, bằng mưu vặt bại.",sk:"Dương khí thịnh — sung sức; phòng bệnh do hoạt động quá độ: tim mạch, huyết áp, mất ngủ vì làm nhiều."},
2:{tf:"«Nguyên hanh, lợi về sự bền chính của ngựa cái; đi trước thì lạc, theo sau thì được chủ; lợi Tây Nam được bạn» — Thuận theo và nâng đỡ thì đại thành.",ty:"Người nhu thuận, bao dung nắm hạnh phúc; đứng sau ủng hộ nhau thay vì giành lái; nữ tính chủ đạo trong quan hệ giai đoạn này.",cv:"Làm phó tướng, hậu phương, thực thi xuất sắc — chưa phải lúc đứng mũi; hợp tác với đội nhóm (Tây Nam = bạn bè) thắng làm một mình.",tc:"Giữ của, tích luỹ theo kiểu đất chở: đều, chậm, chắc; bất động sản, nông nghiệp thuận; kỵ đầu cơ đi trước thị trường.",sk:"Chú ý hệ tiêu hoá, dạ dày (thuộc Thổ); bồi bổ từ từ, dưỡng hơn chữa; đi bộ trên đất, gần thiên nhiên rất hợp."},
3:{tf:"«Nguyên hanh lợi trinh; chớ vội có nơi đến; lợi việc dựng chư hầu» — Buổi đầu gian nan, nên gây dựng nền móng và tìm người phụ tá, chưa nên tiến xa.",ty:"Tình mới nhiều trắc trở ban đầu (gia đình cản, hoàn cảnh khó) — không phải điềm xấu mà là cơn đau mọc mầm; kiên trì và có người mai mối/ủng hộ sẽ thành.",cv:"Khởi nghiệp/dự án mới rối như tơ — đừng mở rộng vội; tuyển 'chư hầu' (cộng sự giỏi) và củng cố nội bộ trước.",tc:"Vốn liếng giai đoạn gieo trồng, chưa có thu; đừng rót thêm vào chỗ chưa rõ; giữ dòng tiền sống qua mùa khó.",sk:"Cơ thể như mầm non: dễ ốm vặt khi giao mùa; bồi dưỡng nền tảng (ngủ, ăn, đề kháng) thay vì thuốc mạnh."},
4:{tf:"«Chẳng phải ta cầu trẻ thơ, trẻ thơ cầu ta; hỏi lần đầu thì đáp, hỏi dai vì ngờ thì không đáp; lợi về sự bền chính» — Thời mông muội cần thầy khai sáng và lòng thành cầu học.",ty:"Chưa hiểu rõ đối phương hoặc chưa hiểu chính lòng mình; đừng thử lòng nhau nhiều lần — hỏi thẳng một lần với lòng thành; nghe lời khuyên người từng trải.",cv:"Việc mới nghề mới còn bỡ ngỡ: tìm mentor, học bài bản; đừng giấu dốt — hỏi đúng người, đúng cách, một lần cho rõ.",tc:"Chưa đủ hiểu biết thì chưa xuống tiền; học tài chính trước khi hành tài chính; cảnh giác người lợi dụng sự thiếu kinh nghiệm của bạn.",sk:"Triệu chứng chưa rõ — đi khám chuyên khoa thay vì tự đoán; nghe phác đồ của một bác sĩ giỏi, đừng chữa theo mười lời mách."},
5:{tf:"«Có lòng thành tin, sáng sủa hanh thông, bền chính thì cát; lợi vượt sông lớn» — Chờ đợi với niềm tin, thời cơ chín sẽ vượt được việc lớn.",ty:"Tình cảm cần thời gian ủ — người kia chưa sẵn sàng, ép sẽ hỏng; chờ trong tư thế đẹp: sống vui, tự chăm mình, giữ liên lạc ấm.",cv:"Đề án đúng nhưng thời chưa đến: hoàn thiện hồ sơ, dưỡng quân, chờ tín hiệu; khi cửa mở thì phải vượt 'sông lớn' ngay không do dự.",tc:"Tiền chưa nên động: giữ vị thế, chờ điểm vào tốt; nuôi quỹ bằng kênh an toàn trong lúc đợi.",sk:"Bệnh cần liệu trình đủ ngày — đừng sốt ruột đổi thuốc; ăn uống điều độ, 'ẩm thực yến lạc' — dưỡng sức chờ thời."},
6:{tf:"«Có lòng tin mà bị chặn; giữa chừng thì cát, theo đến cùng thì hung; lợi gặp đại nhân, không lợi vượt sông lớn» — Tranh tụng nên dừng ở giữa chừng, nhờ người công chính phân xử.",ty:"Cãi vã leo thang thành 'kiện tụng tình cảm' — ai cũng đòi xử thắng; dừng ở thoả hiệp là cát, đấu tới cùng là tan; nhờ người uy tín cả hai nể làm trung gian.",cv:"Tranh chấp hợp đồng, bất đồng nội bộ: hoà giải sớm có lợi, theo kiện tới cùng hao cả thắng lẫn thua; tìm trọng tài công minh.",tc:"Tiền dính tranh chấp: chấp nhận thiệt nhỏ để thoát sớm thường rẻ hơn; không khởi sự đầu tư lớn trong lúc còn vướng kiện cáo.",sk:"Căng thẳng đối đầu bào mòn gan, huyết áp; buông bớt một cuộc chiến là hạ một chỉ số; tránh phẫu thuật/can thiệp lớn lúc tâm chưa an nếu hoãn được."},
7:{tf:"«Bền chính; có bậc trượng nhân cầm quân thì cát, không lỗi» — Việc lớn cần kỷ luật quân đội và người chỉ huy xứng đáng.",ty:"Quan hệ cần 'kỷ luật': nguyên tắc chung, lời hứa được giữ; một người phải đứng ra dẫn dắt giai đoạn khó — với sự đồng thuận, không phải áp đặt.",cv:"Dẫn đội qua chiến dịch lớn: cần danh chính, kỷ luật, thưởng phạt rõ; chọn tướng đúng — người thâm niên đức độ, không giao quyền cho kẻ háo thắng.",tc:"Chi tiêu như nuôi quân: có ngân sách, có hậu cần, có dự phòng; đầu tư theo chiến dịch có kế hoạch rút lui rõ ràng.",sk:"Rèn thể lực có giáo án, kỷ luật như quân ngũ; bệnh cần 'tổng tấn công' đúng phác đồ — đủ liều, đủ ngày, có bác sĩ 'cầm quân'."},
8:{tf:"«Cát. Xét lại mình: lớn lao, dài lâu, bền chính thì không lỗi; kẻ bất an sẽ tìm đến; ai đến muộn thì hung» — Thời liên kết quanh một trung tâm xứng đáng, kết giao sớm thì lợi.",ty:"Duyên đến từ sự nương tựa chân thành; chủ động gắn bó sớm — chần chừ để 'xem thêm' sẽ lỡ; chọn người đáng tựa rồi hết lòng.",cv:"Gia nhập liên minh, về đội mạnh, kết nối với người dẫn đầu uy tín; ai vào sớm được chỗ tốt; xét kỹ 'trung tâm' mình theo có xứng không.",tc:"Hùn vốn, hợp tác tài chính quanh người có đức có tài; vào sớm hưởng phần thuận; đến trễ chỉ còn phần rủi.",sk:"Sức khoẻ nhờ cộng đồng: nhóm tập, bạn đồng hành giữ nếp; nước là hành chủ — uống đủ, chú ý thận, bàng quang."},
9:{tf:"«Hanh thông; mây dày mà chưa mưa, từ cõi tây của ta» — Sức tích còn nhỏ, kìm hãm nhẹ; hoàn thiện việc nhỏ chờ mưa xuống.",ty:"Tình cảm bị níu bởi điều nhỏ (khoảng cách, lịch bận, hiểu lầm vặt) — không nghiêm trọng nhưng chưa 'mưa'; chăm chút cử chỉ nhỏ, thời điểm ngọt sẽ tới.",cv:"Việc lớn chưa chín, việc nhỏ đầy cơ hội: hoàn thiện kỹ năng, tinh chỉnh sản phẩm; tích từng chút — mây đủ dày ắt mưa.",tc:"Tích tiểu thành đại: tiết kiệm đều, khoản nhỏ sinh khoản lớn; chưa phải lúc đánh lớn — sức chứa còn mỏng.",sk:"Điều chỉnh nhỏ tạo khác biệt: bớt muối, thêm rau, ngủ sớm nửa giờ; bệnh nhẹ chữa ngay kẻo tích thành nặng."},
10:{tf:"«Dẫm đuôi hổ, hổ không cắn người; hanh thông» — Đi trong nguy hiểm bằng lễ độ, cẩn trọng thì an.",ty:"Yêu người 'khó' hoặc hoàn cảnh nhạy cảm — như dẫm đuôi hổ: được, miễn đủ tinh tế, lễ độ, biết lúc nào im; sai một câu vụng là 'bị cắn'.",cv:"Làm việc với sếp lớn, khách khó, đối tác quyền thế: giữ đúng vai, đúng lễ, chuẩn từng chi tiết — họ sẽ nể; sơ suất kiêu ngạo sẽ trả giá ngay.",tc:"Giao dịch rủi ro cao cần quy trình chặt: đọc kỹ, hỏi kỹ, đi từng bước có kiểm tra; mạo hiểm có lễ pháp thì qua, liều ẩu thì mất.",sk:"Đang 'đi trên băng mỏng': bệnh nền, thể trạng yếu — vẫn sinh hoạt được nếu tuân thủ nghiêm ngặt chỉ định; chủ quan là tái phát."},
11:{tf:"«Nhỏ đi, lớn đến; cát, hanh thông» — Trời đất giao hoà, trên dưới thông suốt; thời thịnh trị.",ty:"Giai đoạn đẹp nhất của giao cảm: hai bên thật lòng trao đổi, gia đình thuận, tiến tới hôn nhân rất hợp thời; giữ thói quen lắng nghe để thịnh không sinh kiêu.",cv:"Trên dưới một lòng, đề xuất được duyệt, hợp tác nở rộ; tận dụng thời thái để làm việc khó nhất trong danh sách của bạn.",tc:"Tài vận hanh thông, đầu tư mở rộng thuận; nhớ quy luật 'trong thái có bĩ': chốt lời có kỷ luật, dựng quỹ phòng khi vận đổi.",sk:"Khí huyết lưu thông tốt, tinh thần thư thái; duy trì vận động đều; thời điểm tốt để trị dứt bệnh cũ còn dây dưa."},
12:{tf:"«Bĩ không phải đạo người; không lợi cho sự bền chính của quân tử; lớn đi nhỏ đến» — Trời đất không giao, thời bế tắc; quân tử thu mình giữ đức.",ty:"Hai người 'ông nói gà bà nói vịt' — kênh giao cảm tắc; đừng cố giải quyết chuyện lớn lúc này, giữ tử tế tối thiểu và chờ khí thông; tiểu nhân xúi bẩy — bịt tai lại.",cv:"Thời không thuận: đề xuất bị ngâm, người xấu đắc thế; ẩn mình làm tốt việc bổn phận, không phô tài, không cãi tay đôi; bĩ cực sẽ thái lai.",tc:"Không đầu tư lớn, không khởi sự; tiền nằm im là tiền khôn lúc này; cảnh giác lời mời 'cứu vãn tình thế' — thời bĩ lắm bẫy.",sk:"Khí trệ: dễ mệt mỏi, khó thở, tiêu hoá kém; tập thở, đi bộ, khai thông vận động nhẹ; đừng phẫu thuật/trị liệu lớn nếu hoãn được."},
13:{tf:"«Đồng nhân ở cánh đồng, hanh thông; lợi vượt sông lớn, lợi sự bền chính của quân tử» — Đồng lòng công khai rộng rãi thì việc lớn thành.",ty:"Tình yêu nảy nở từ chung chí hướng (đồng nghiệp, bạn học, cùng đam mê); công khai quang minh thì bền — tình vụng trộm nơi 'xó tối' trái tinh thần quẻ.",cv:"Sức mạnh liên minh: dự án chung, hợp lực liên phòng ban, cộng đồng nghề; minh bạch mục tiêu chung trước, lợi ích riêng sẽ theo sau.",tc:"Góp vốn công khai, cổ phần minh bạch thắng; quỹ chung phải có quy chế rõ từ ngày đầu — 'đồng' ở cánh đồng, không 'đồng' sau cánh cửa.",sk:"Tập cùng cộng đồng bền hơn tập một mình; bệnh nên tham vấn hội chẩn nhiều chuyên khoa nếu phức tạp."},
14:{tf:"«Nguyên hanh» — Sở hữu lớn, cực kỳ hanh thông; mặt trời giữa trời soi khắp.",ty:"Tình cảm viên mãn, được nhiều người chúc phúc; người có 'ánh sáng' (địa vị, nhân cách) đến với bạn; giàu tình thì nhớ chia sẻ — giữ khiêm cung để phúc bền.",cv:"Đỉnh cao thành tựu: nắm nguồn lực lớn, uy tín sáng; dùng vị thế nâng người khác lên — 'ngăn ác, dương thiện' — là cách giữ vận này lâu.",tc:"Của cải lớn về tay: thu hoạch, thắng đậm; quản trị chuyên nghiệp ngay — tài sản lớn không quản là hoạ; chia sẻ, đóng góp mở phúc.",sk:"Thể trạng sung mãn; cảnh giác bệnh 'nhà giàu': ăn ngon quá độ, mỡ máu, gout; kiểm soát tiệc tùng khi vận đang thịnh."},
15:{tf:"«Hanh thông; quân tử giữ được trọn vẹn đến cùng» — Khiêm nhường: quẻ duy nhất sáu hào đều tốt.",ty:"Người khiêm ái ngôn hoà thắng mọi trái tim; nhường một câu, cúi một chút — tình cảm êm như nước; khoe khoang lúc này làm mất duyên.",cv:"Càng giỏi càng nên nhún: công lao để người khác kể thay; vị trí cao ứng xử thấp — được cả lòng trên lẫn dưới; mọi việc theo hướng khiêm đều hanh.",tc:"Ăn chắc mặc bền, không khoe của; đầu tư khiêm tốn đều đặn thắng phô trương; san bớt chỗ thừa đắp chỗ thiếu — cân đối danh mục.",sk:"Sống điều độ, thanh đạm là thuốc trường thọ của quẻ này; tập nhẹ mà đều: thái cực, đi bộ, yoga."},
16:{tf:"«Lợi việc dựng tướng, ra quân» — Hân hoan thuận thời; sấm rền báo xuân, lòng người phấn chấn.",ty:"Niềm vui mới làm quan hệ bừng dậy: chuyến đi chung, kế hoạch chung khiến hai người 'cùng nhịp trống'; đừng để vui thành lời hứa suông — vui phải ra việc.",cv:"Thời điểm phát động: ra mắt, khởi công, truyền cảm hứng đội nhóm; chuẩn bị từ trước rồi 'nổi trống' đúng lúc lòng người đang hướng về.",tc:"Tâm lý thị trường hưng phấn — thuận cho ra hàng, mở bán; nhưng chính lúc hồ hởi phải giữ đầu lạnh: vui quá dễ xuống tiền ẩu.",sk:"Tinh thần phấn chấn kéo sức khoẻ lên; cẩn thận 'dự' thành 'dật' — ham vui bỏ nếp: thức khuya, ăn uống thả — giữ chừng mực."},
17:{tf:"«Nguyên hanh lợi trinh, không lỗi» — Theo thời mà động, biết theo đúng người đúng lẽ thì hanh thông.",ty:"Bớt cố chấp 'phải theo ý mình': thuận theo nhịp của người kia một giai đoạn, tình sẽ mềm lại; chọn người xứng đáng để 'theo' — theo đúng người là hạnh phúc, theo sai là lệ thuộc.",cv:"Thời thế đổi — đổi theo: quy trình mới, sếp mới, xu hướng mới; kẻ thích nghi nhanh thắng kẻ giỏi mà cứng; chọn đúng người dẫn dắt mà đi theo.",tc:"Đầu tư theo xu hướng lớn có kiểm chứng, không nghịch dòng; linh hoạt cơ cấu danh mục theo thời.",sk:"Thuận theo nhịp sinh học: ngủ khi tối, dậy khi sáng, ăn theo mùa; nghe cơ thể thay vì ép nó theo lịch cứng."},
18:{tf:"«Nguyên hanh, lợi vượt sông lớn; trước ngày Giáp ba ngày, sau ngày Giáp ba ngày» — Sửa cái đổ nát: tính kỹ trước khi làm, theo dõi kỹ sau khi làm.",ty:"Quan hệ có 'mọt' tích tụ lâu ngày (thói quen xấu, chuyện cũ chưa giải); can đảm mổ xẻ tận gốc — trước khi nói chuyện chuẩn bị kỹ, sau khi nói giữ gìn kỹ; sửa được thì tình như mới.",cv:"Tiếp quản mớ hỗn độn, sửa sai hệ thống cũ (kể cả lỗi người tiền nhiệm); lập kế hoạch 3 bước trước – 3 bước sau; đây là công trạng lớn nếu làm tới nơi.",tc:"Tổng rà soát tài chính mục ruỗng: nợ cũ, khoản rò, hợp đồng thiệt; cắt sửa dứt điểm một lần — vá víu chỉ nuôi mọt.",sk:"Bệnh tích tụ do nếp cũ lâu năm — trị tận gốc bằng thay đổi lối sống, không chỉ uống thuốc chặn triệu chứng; kiên trì trước sau."},
19:{tf:"«Nguyên hanh lợi trinh; đến tháng tám có hung» — Thời tiến tới, dương khí lớn dần; thịnh mà phải phòng suy.",ty:"Giai đoạn quan hệ ấm lên rõ rệt — gần gũi, chăm sóc, đi đến gắn bó; tận hưởng và vun trồng, nhưng đừng phung phí sự nồng ấm: giữ nhịp bền hơn đốt cháy.",cv:"Cơ hội đang mở, cấp trên để mắt, đề bạt trong tầm; tiến tới chủ động, giám sát công việc sát sao; nhớ chuẩn bị phương án cho lúc chu kỳ đảo chiều.",tc:"Tài lộc vào mùa lớn; đầu tư thuận nhưng chốt kế hoạch rút trước khi vào — 'tháng tám có hung' là lời nhắc chu kỳ nào cũng có đỉnh.",sk:"Sức khoẻ đi lên — thời điểm vàng xây nền thể lực; đừng ỷ khoẻ mà phá: chu kỳ xuống sẽ đòi nợ."},
20:{tf:"«Rửa tay mà chưa dâng lễ; có lòng thành, dáng nghiêm trang» — Thời quan sát và được quan sát; xem xét sâu rồi mới hành động.",ty:"Dừng lại quan sát mối quan hệ như người ngoài: cách hai người cư xử khi mệt, khi vui, với người khác — sự thật nằm ở đó; bạn cũng đang được 'xem' — sống sao cho đáng.",cv:"Chưa vội quyết: quan sát toàn cục, thị trường, lòng người; vị trí của bạn có tính làm gương — mỗi cử chỉ đều được nhìn; thanh tra, đánh giá, khảo sát là việc hợp thời.",tc:"Đứng ngoài thị trường quan sát một nhịp; nghiên cứu kỹ rồi mới vào tiền; xem cách một công ty/người đối xử lúc khó khăn trước khi hùn.",sk:"Tự quan sát cơ thể: đo đạc, khám tổng quát, ghi nhật ký sức khoẻ; hiểu rõ nền tảng rồi mới chọn phương pháp."},
21:{tf:"«Hanh thông; lợi dụng hình ngục» — Cắn xuyên vật cản: dùng biện pháp cứng rắn công minh loại bỏ chướng ngại.",ty:"Có 'cái xương' mắc giữa hai người: hiểu lầm cũ, người thứ ba, thói quen gây tổn thương — phải cắn vỡ nó bằng cuộc đối thoại quyết liệt mà công bằng; né tránh thì miệng không khép lại được.",cv:"Xử lý dứt điểm vật cản: nhân sự phá hoại, quy trình tắc, hợp đồng vi phạm; dùng kỷ luật và pháp lý đúng mực — công minh thì hanh thông.",tc:"Đòi nợ, xử lý tranh chấp tiền bằng con đường chính thức; cắt hợp đồng thiệt hại dù mất phí phạt — để lâu thiệt hơn.",sk:"Chú ý răng miệng, nhai nuốt, tiêu hoá; khối u, dị vật cần can thiệp sớm dứt khoát theo chỉ định — đừng nuôi 'vật cản' trong người."},
22:{tf:"«Hanh thông; hơi lợi khi có việc phải đi» — Trang sức, vẻ đẹp; tốt cho việc nhỏ, việc lớn cần chất thật.",ty:"Giai đoạn 'trang điểm' cho tình yêu: hẹn hò đẹp, lời ngọt, hình thức chỉn chu — đáng yêu, miễn đừng chỉ có thế; hỏi: sau lớp lung linh, hai người có thật hiểu nhau?",cv:"Chăm sóc hình ảnh, hồ sơ, bao bì, thương hiệu — đúng thời; nhưng quyết định lớn phải dựa thực chất; cẩn thận báo cáo đẹp che số liệu xấu.",tc:"Chi cho hình thức có chừng mực sinh lợi (thương hiệu, trưng bày); đừng mua tài sản vì vẻ ngoài — soi kỹ 'ruột' trước khi trả giá.",sk:"Đẹp từ gốc: da, dáng phản ánh nội tiết, tiêu hoá, giấc ngủ; mỹ phẩm không thay được nếp sống; cẩn thận can thiệp thẩm mỹ thiếu an toàn."},
23:{tf:"«Không lợi khi có việc phải đi» — Thời bóc mòn, âm leo bào dương; giữ hạt giống cuối chờ hồi sinh.",ty:"Quan hệ đang bị bào từng lớp: niềm tin sứt, người xấu chen lời; đừng quyết định lớn hay níu kéo gắng gượng — giữ phần tử tế cốt lõi ('quả lớn không bị ăn') và chờ chu kỳ đổi.",cv:"Thế suy: dự án teo, phe cánh lấn; không phải lúc ra đòn — bảo toàn uy tín và năng lực lõi, chờ 'Phục' (hồi sinh) đến sau 'Bác'.",tc:"Tài sản đang thời rơi rụng: không bắt dao rơi, không gồng lỗ thêm; giữ chặt phần vốn cuối — đó là hạt giống mùa sau.",sk:"Đề kháng suy giảm, bệnh dễ 'bóc' sức từng lớp; ưu tiên ngủ, dinh dưỡng, tránh nơi dịch bệnh; bảo toàn sức là chiến lược duy nhất đúng lúc này."},
24:{tf:"«Hanh thông; ra vào không bệnh, bạn đến không lỗi; đạo trở lại, bảy ngày trở về; lợi khi có việc phải đi» — Một dương hồi sinh; ánh sáng quay về sau ngày tối nhất.",ty:"Tình cảm hồi sinh: làm lành, người cũ trở lại đúng nghĩa, hoặc trái tim bạn ấm lại sau băng giá; nuôi ngọn lửa nhỏ này nhẹ nhàng — đừng thổi bùng vội.",cv:"Khởi động lại sau thất bại: dự án tái sinh, cơ hội mới từ nền cũ; đi từng bước theo chu kỳ tự nhiên, có bạn đồng hành thì càng thuận.",tc:"Dòng tiền bắt đầu quay lại; vào vị thế từng phần nhỏ theo đà hồi phục; kiên nhẫn — 'bảy ngày trở về' là quy luật, không phải phép màu một đêm.",sk:"Giai đoạn hồi phục thật sự: bệnh lui, sức về từng ngày; tuân thủ nhịp điều dưỡng, chớ vội vận động mạnh khi mầm dương còn non."},
25:{tf:"«Nguyên hanh lợi trinh; không chính thì gặp hoạ, không lợi khi có việc phải đi» — Không càn bậy: hành động thuận thiên, động cơ trong sáng thì đại thành.",ty:"Yêu không toan tính, không kịch bản — sự chân thật là bùa hộ mệnh; nếu điều xấu xảy đến không do lỗi bạn, đừng vá víu bằng mưu — cứ ngay thẳng, nó tự qua.",cv:"Làm đúng bổn phận với động cơ sạch, thành công tự đến; mưu cầu quá phận hoặc đi đường tắt lúc này chuốc hoạ; gặp sự cố ngoài ý muốn — bình tĩnh, đừng chữa bậy.",tc:"Tiền kiếm chính đạo bền, tiền đầu cơ may rủi hoạ; nếu dính 'tai bay vạ gió' tài chính không do mình — xử lý theo luật, đừng gỡ bằng liều.",sk:"Bệnh 'vô vọng chi tật' — đến không do lỗi mình: đừng hoảng chữa lung tung, giữ nếp lành nó tự lui; thuận tự nhiên là phương thuốc chủ."},
26:{tf:"«Lợi sự bền chính; không ăn cơm nhà mà cát; lợi vượt sông lớn» — Tích lũy lớn: nuôi tài đức, gánh việc chung, đủ lực thì làm việc lớn.",ty:"Tình cảm được 'nuôi lớn' qua thử thách và thời gian — sức nén càng lâu, bung càng bền; giai đoạn kiềm chế (xa cách, chờ đợi) chính là đang tích của cho mai sau.",cv:"Học sâu, rèn bản lĩnh, nhận việc khó ngoài vùng quen ('không ăn cơm nhà') — bạn đang được nuôi thành người gánh việc lớn; đủ lực rồi hãy vượt sông.",tc:"Tích sản mạnh mẽ: học đầu tư nghiêm túc, gom vốn tri thức lẫn tiền; khoản để dành lúc này là 'đại súc' — nền cho cú nhảy lớn sắp tới.",sk:"Bồi bổ nền tảng dài hạn: cơ bắp, xương khớp, thể lực bền; kiêng khem đúng lúc chính là tích sức."},
27:{tf:"«Bền chính thì cát; xem cách nuôi dưỡng, tự tìm miếng ăn cho mình» — Cái miệng: cẩn thận điều vào (thức ăn) và điều ra (lời nói).",ty:"Lời nói nuôi hoặc giết tình cảm: bớt lời chê, thêm lời lành; nhìn cách một người 'nuôi' bản thân và người khác — đó là nhân cách thật của họ.",cv:"Uy tín từ cái miệng: hứa ít làm nhiều, phát ngôn chuẩn; nghề liên quan ăn uống, đào tạo, nội dung có lộc; tự nuôi mình bằng nghề chính đáng.",tc:"Xem lại 'nguồn nuôi': thu nhập có sạch, có bền không; đừng thèm phần của người — 'nhìn miếng ăn kẻ khác' là điềm xấu của quẻ.",sk:"Trọng tâm là ăn uống: chất lượng thực phẩm, cách ăn, giờ ăn; răng miệng, dạ dày, đại tràng cần chú ý; nói ít lại cũng là dưỡng khí."},
28:{tf:"«Xà nhà oằn cong; lợi khi có việc phải đi, hanh thông» — Quá tải phi thường: cần chỗ dựa chắc và hành động phi thường.",ty:"Quan hệ đang gánh sức ép vượt ngưỡng (xa cách dài, biến cố gia đình, chênh lệch lớn); đây là thời khắc 'phi thường' — hoặc cùng nhau làm điều can đảm khác thường, hoặc xà gãy; đừng chất thêm gánh.",cv:"Nhiệm vụ vượt sức thường: khủng hoảng, dự án sống còn; dám đứng một mình không sợ, nhưng phải gia cố 'cột chống' (người hỗ trợ, nguồn lực) trước khi nhận thêm bất cứ gì.",tc:"Đòn bẩy đã căng — giảm nợ, không all-in thêm; nếu buộc phải hành động lớn, làm dứt khoát một lần với phương án thoát hiểm rõ.",sk:"Cơ thể quá tải trầm trọng: tim, huyết áp, cột sống đang 'oằn'; giảm tải NGAY — nghỉ, giảm cân, giảm việc; đây là cảnh báo đỏ, không phải lời khuyên."},
29:{tf:"«Hiểm trùng hiểm; có lòng thành tin, giữ tâm thì hanh, hành động có công» — Nước sâu tầng tầng: giữ lòng tin làm phao, đầy chỗ trũng này rồi qua chỗ kế.",ty:"Sóng gió nối nhau — đừng đòi giải quyết hết một lúc; qua từng chuyện một như nước đầy từng vực; giữ lòng thành làm phao chung: còn tin nhau thì còn qua được.",cv:"Khó khăn chồng khó khăn: xử lý tuần tự, không nhảy cóc, không liều thoát nhanh; kinh nghiệm vượt hiểm lần này thành 'nghề' của bạn về sau.",tc:"Vùng nước xoáy tài chính: chỉ giữ thanh khoản và trả nợ đúng hạn; mọi 'cửa thoát nhanh' đều là xoáy sâu hơn; qua từng kỳ một.",sk:"Bệnh dai dẳng từng đợt: kiên trì trị theo đợt, đủ liệu trình; chú ý thận, tai, tuần hoàn (hành Thủy); giữ tinh thần — lo sợ làm bệnh sâu thêm."},
30:{tf:"«Lợi sự bền chính, hanh thông; nuôi trâu cái thì cát» — Lửa sáng nhờ bám đúng chỗ; sáng suốt đi cùng nhu thuận.",ty:"Tình rực rỡ như lửa — đẹp nhưng cần 'củi' để bám: sự gắn bó, sinh hoạt chung, mục tiêu chung; nuôi phần dịu dàng ('trâu cái') để lửa ấm mà không đốt nhau.",cv:"Toả sáng đúng sân khấu: thuyết trình, truyền thông, nghệ thuật, giáo dục; chọn đúng nơi 'bám' (công ty, nền tảng) — lửa rời củi thì tắt; sáng suốt kèm khiêm nhu thì bền.",tc:"Nguồn thu từ danh tiếng, trí tuệ, hình ảnh — vượng; nhưng lửa bốc thì nhanh tàn: chuyển hoá danh thành tài sản thật (kỹ năng, hệ thống, tích sản).",sk:"Chú ý tim, mắt, huyết áp, viêm nhiệt (hành Hỏa); cân bằng bằng mát: ngủ đủ, bớt cay nóng, thiền định cho 'lửa' cháy êm."},
31:{tf:"«Hanh thông, lợi sự bền chính; cưới vợ thì cát» — Cảm ứng đôi bên: núi đội đầm, khí giao hoà; quẻ của tình yêu chớm.",ty:"Rung động thật sự và được đáp lại — quẻ đẹp bậc nhất cho tỏ tình, cưới hỏi; bí quyết: cảm nhau bằng sự trống rỗng thành tâm — đến với nhau không toan tính, không phòng thủ.",cv:"Thời của 'chemistry': phỏng vấn hợp ý, đối tác tâm đầu, khách hàng cảm mến; giao tiếp bằng lắng nghe thật — sự chân thành đang có sức hút lạ.",tc:"Hợp tác dựa trên tin cảm tiến triển nhanh; tuy vậy cảm tình không thay hợp đồng — quý mến nhau xong vẫn ký giấy rõ ràng.",sk:"Nhạy cảm gia tăng — tốt cho trực giác cơ thể; để ý cảm xúc ảnh hưởng nội tiết; các liệu pháp chạm (massage, bấm huyệt) hiệu quả cao lúc này."},
32:{tf:"«Hanh thông, không lỗi, lợi sự bền chính; lợi khi có việc phải đi» — Bền lâu: sấm gió theo nhau không đổi lối; giữ đạo thường.",ty:"Chìa khoá là sự thường hằng: nghi thức nhỏ lặp lại (bữa cơm chung, lời chào sáng) giữ hôn nhân hơn mọi lãng mạn lớn; chán không phải hết yêu — là thiếu nhịp chung, tạo lại nhịp đi.",cv:"Kiên trì con đường đã chọn: nghề đã bén, hướng đã đúng — đừng nhảy vì cỏ bên kia xanh; đổi mới cách làm nhưng không rời gốc nghề.",tc:"Đầu tư trường kỳ, đóng đều như máy; sức mạnh của bạn lúc này là lãi kép và thói quen — kẻ thù là sự sốt ruột.",sk:"Sức khoẻ = thói quen × thời gian: bài tập cũ duy trì đủ lâu thắng giáo án mới bỏ dở; bệnh mạn tính sống chung hoà bình bằng kỷ luật đều đặn."},
33:{tf:"«Hanh thông; việc nhỏ lợi về sự bền chính» — Lui ẩn đúng lúc: rút sớm khi còn rút đẹp được.",ty:"Lùi một bước cứu một mối tình: bớt kiểm soát, bớt hiện diện dày đặc — khoảng cách đúng lúc làm người kia nhìn rõ giá trị của bạn; nếu quan hệ độc hại: đây là quẻ cho phép rời đi tử tế.",cv:"Rút lui chiến lược: thoái khỏi dự án xấu dần, giữ khoảng cách với nhóm quyền lực đang đấu đá; rút trong danh dự, không tuyên chiến — người khôn thoát trước khi cửa hẹp.",tc:"Chốt vị thế, thoát hàng khi thị trường còn cho giá đẹp; giảm quy mô, tăng tiền mặt; 'độn' là bảo toàn — không phải bỏ chạy.",sk:"Cơ thể xin rút khỏi guồng quay: nghỉ dưỡng, tĩnh tâm, giảm cam kết xã hội; bệnh cần tránh xa nguồn hại (rượu, khói, người gây stress) — tránh hẳn, không 'giảm dần'."},
34:{tf:"«Lợi về sự bền chính» — Cường tráng: sấm trên trời, sức mạnh thịnh; mạnh phải đi với chính.",ty:"Giai đoạn tự tin theo đuổi mạnh mẽ — hấp dẫn đấy; nhưng nhớ hình ảnh 'dê húc giậu kẹt sừng': ép người quá, đòi hỏi quá sẽ mắc kẹt trong chính sự hung hăng của mình; mạnh mà lễ độ mới thắng.",cv:"Khí thế dâng cao, đủ lực đẩy việc lớn; kỷ luật quyết định thành bại: đúng quy trình, đúng pháp, không cậy mạnh vượt rào — sức lớn dùng sai chỗ thành tự hại.",tc:"Đà tăng mạnh — theo đà nhưng có điểm dừng chốt sẵn; không dùng sức mạnh tài chính chèn ép đối tác nhỏ: quả báo của quẻ này đến nhanh.",sk:"Thể lực đỉnh cao — thời điểm lập kỷ lục cá nhân; rủi ro lớn nhất là chấn thương do quá tự tin: khởi động kỹ, tăng tải từ từ, đúng kỹ thuật."},
35:{tf:"«Bậc hầu được ban ngựa nhiều bầy, một ngày tiếp kiến ba lần» — Tiến lên như mặt trời mọc; được bề trên tin dùng.",ty:"Quan hệ 'lên hạng': được giới thiệu với gia đình, bạn bè, công khai rạng rỡ; tình cảm tiến bộ nhìn thấy được từng tuần — cứ đà trong sáng ấy mà tiến.",cv:"Vận thăng tiến rõ: sếp tin, giao việc lớn, gặp gỡ liên tục; tiến bằng cống hiến trong sáng, không giành công — mặt trời không cần chen lấn vẫn mọc.",tc:"Thu nhập tăng theo vị thế; nhận 'ngựa ban' (thưởng, cổ phần, đãi ngộ) một cách xứng đáng; đầu tư theo đà sáng nhưng từng bước có kiểm chứng.",sk:"Năng lượng buổi 'mặt trời mọc': dậy sớm, tận dụng buổi sáng; sức khoẻ tiến bộ đều nếu gắn với lịch cố định buổi sáng."},
36:{tf:"«Lợi về sự gian nan bền chính» — Ánh sáng bị thương: mặt trời lặn vào lòng đất; giấu sáng giữ mình chờ thời.",ty:"Giai đoạn phải 'giấu sáng': tình cảm chưa thể công khai, hoặc bạn bị hiểu lầm oan — đừng gào lên thanh minh; giữ phẩm giá trong im lặng, thời gian sẽ minh oan; cẩn trọng người soi mói chuyện riêng.",cv:"Môi trường bất lợi cho người tài: sếp tối, kẻ xấu nắm quyền; như Cơ Tử giả ngây — làm tròn phận, giấu tài, không tranh sáng với kẻ đang cầm đèn; âm thầm chuẩn bị đường ra.",tc:"Giấu bớt 'ánh sáng' tài chính: không khoe thu nhập, không phô tài sản; thời điểm dễ bị nhòm ngó, vay mượn, lừa gạt — kín đáo là két sắt tốt nhất.",sk:"Tổn thương âm ỉ bên trong: khám sâu chứ đừng nhìn bề mặt; sức khoẻ tinh thần đang 'bị thương trong bóng tối' — tìm người tin cậy để nói ra."},
37:{tf:"«Lợi về sự bền chính của người nữ» — Người trong nhà: nề nếp gia đình lan thành phong hoá; sửa nhà trước, thiên hạ sau.",ty:"Trọng tâm là mái ấm: phân vai rõ, lời nói trong nhà có tình có lý; hôn nhân bền nhờ người giữ lửa được trân trọng; mọi rắc rối bên ngoài — về nhà giải quyết gốc trước.",cv:"'Tề gia' rồi mới 'trị quốc': đội nhóm như gia đình cần vai trò rõ, quy tắc ấm mà nghiêm; doanh nghiệp gia đình vào thời thuận; hậu phương ổn thì tiền tuyến thắng.",tc:"Tài chính gia đình là ưu tiên: ngân sách chung minh bạch, quỹ giáo dục con, bảo hiểm cho trụ cột; 'nữ chính' — người quản chi tiêu đảm sẽ giữ được của.",sk:"Sức khoẻ cả nhà cùng nếp: bữa cơm nhà, giờ ngủ chung nhịp; chăm người già trẻ nhỏ trong nhà đúng lúc — phúc khí của quẻ này nằm ở đó."},
38:{tf:"«Việc nhỏ thì cát» — Chia lìa trái ngược: lửa bốc lên, đầm chảy xuống; tìm điểm đồng trong dị.",ty:"Hai người đang nhìn hai hướng: giá trị khác, nhịp sống khác — đừng ép hợp nhất mọi thứ; bắt đầu từ những điểm chung nhỏ (một bữa ăn, một thói quen) để nối lại; khác biệt được tôn trọng có thể thành sức hút.",cv:"Nội bộ chia phe, đối tác nghịch ý: chưa gỡ được đại cục thì thắng từng việc nhỏ; hợp tác giới hạn trong phạm vi cùng lợi ích — không đòi đồng thuận toàn diện.",tc:"Quan điểm tài chính vênh nhau (vợ chồng, cổ đông): tách bạch phần chung tối thiểu và phần riêng tự quyết; giao dịch nhỏ lẻ được, khoản lớn chờ đồng thuận.",sk:"Cơ thể 'trên nóng dưới lạnh', âm dương nghịch: rối loạn thần kinh thực vật, nóng trong lạnh ngoài; điều hoà từ từ bằng ăn uống quân bình, tránh cực đoan nóng/lạnh."},
39:{tf:"«Lợi Tây Nam, không lợi Đông Bắc; lợi gặp đại nhân, bền chính thì cát» — Gian truân: nước hiểm trước, núi chắn sau; lui về sửa mình, tìm người giỏi mà theo.",ty:"Tiến thoái lưỡng nan trong tình cảm — càng cố càng kẹt; đổi hướng: về 'Tây Nam' (chốn dễ, người hiền) — nhờ người từng trải khuyên giải; và trước hết quay về sửa chính mình thay vì sửa người kia.",cv:"Đường thẳng bị chặn: dự án kẹt, cửa chính đóng; đừng húc — tìm đường vòng dễ đi hơn, tìm 'đại nhân' (người có thế lực, chuyên gia) dẫn qua đèo; gặp khó phản tỉnh — lỗi hệ thống nằm đâu?",tc:"Thanh khoản kẹt, khoản đầu tư mắc cạn: không bơm thêm vào chỗ kẹt; đi đường vòng — tái cấu trúc, bán bớt phần dễ bán; nhờ tư vấn chuyên nghiệp gỡ.",sk:"Chân, khớp, vận động là điểm yếu (Kiển = què chân); đau đâu nghỉ đó, trị liệu bài bản với chuyên gia — tự nắn tự chữa làm nặng thêm."},
40:{tf:"«Lợi Tây Nam; không phải đi đâu thì quay về là cát; còn việc phải đi thì đi sớm là cát» — Cởi mở tan băng: sấm mưa nổi, bế tắc được giải.",ty:"Nút thắt được gỡ: hiểu lầm tan, giận hờn xả — tha thứ nhanh, xoá lỗi cũ, đừng nhắc lại; hành động hoà giải nào định làm thì làm SỚM, để lâu khí giải lại đóng.",cv:"Khủng hoảng qua đỉnh: xử nhanh phần còn đọng rồi trở về nhịp thường; ân xá lỗi cũ của cộng sự, tha cho cả chính mình; đừng ở lại 'chế độ chiến đấu' khi cuộc chiến đã xong.",tc:"Khoản treo được giải ngân, nợ nần đàm phán được; tất toán dứt điểm những dây dưa tài chính ngay khi cửa mở — cơ hội giải thoát không mở lâu.",sk:"Bệnh đến hồi 'giải': triệu chứng lui, thuốc đáp ứng; hoàn thành nốt liệu trình sớm và dứt điểm; xả stress tồn đọng bằng vận động ra mồ hôi."},
41:{tf:"«Có lòng thành, cả tốt, không lỗi, có thể bền chính; hai giỏ cơm đạm bạc vẫn dâng cúng được» — Bớt đi để được: giảm cái thừa, nuôi cái thiếu.",ty:"Bớt cái tôi, bớt đòi hỏi — tình cảm liền tăng; giai đoạn 'nghèo mà vui' của đôi lứa: hai giỏ cơm đạm bạc với lòng thành hơn mâm cao thiếu tình; hy sinh có tính toán cho tương lai chung.",cv:"Cắt giảm để mạnh: bỏ việc rườm, thu gọn dự án, giảm hình thức; nguồn lực dồn cho lõi; chịu thiệt ngắn hạn (lương, chức) đổi lấy vị thế dài hạn — đúng thời của nó.",tc:"Thắt lưng buộc bụng chủ động: cắt chi xa xỉ, giảm nợ, sống dưới mức thu nhập; khoản 'tổn' hôm nay là khoản 'ích' ngày mai — quẻ sau của Tổn chính là Ích.",sk:"Bớt là thuốc: bớt ăn (ăn kiêng khoa học), bớt màn hình, bớt độc tố; thanh lọc, nhịn ăn gián đoạn có hướng dẫn hợp thời điểm này."},
42:{tf:"«Lợi khi có việc phải đi, lợi vượt sông lớn» — Tăng ích: bớt trên thêm dưới, gió sấm giúp nhau; thời được trợ lực lớn.",ty:"Thời 'cho là nhận': đầu tư vào người mình thương — thời gian, sự chú ý, lời động viên — sẽ nhận lại gấp bội; quan hệ đang được 'gió sấm' đẩy: tiến tới nhanh, kể cả việc lớn (cầu hôn, về chung).",cv:"Vận may có người giúp: cấp trên trao cơ hội, quý nhân mở đường; thấy điều hay theo ngay, có lỗi sửa liền — tốc độ thiện chí của bạn quyết định độ lớn của 'ích'; dám nhận việc lớn.",tc:"Thời điểm hiếm để đầu tư mạnh: vốn được tiếp, dự án được rót; tiền đẻ ra tiền khi đi cùng việc thiện lành; chia sẻ một phần lộc — giữ đạo 'bớt trên thêm dưới' thì lộc bền.",sk:"Cơ thể hấp thu tốt — thời điểm vàng để bồi bổ, tăng cơ, phục hồi; đầu tư cho sức khoẻ (thiết bị, khoá tập, dinh dưỡng) lúc này lãi nhất."},
43:{tf:"«Tuyên cáo ở sân vua, thành thật hô lên rằng có nguy; báo cho ấp mình, không lợi việc binh đao; lợi khi có việc phải đi» — Quyết liệt loại trừ cái xấu cuối cùng, công khai mà không bạo lực.",ty:"Đến lúc nói dứt khoát điều nhịn đã lâu: ranh giới, điều không chấp nhận — công khai, bình tĩnh, không đánh úp; 'cái xấu' chỉ còn một nhưng đừng khinh suất: sự dứt khoát nửa vời sẽ để nó mọc lại.",cv:"Xử lý dứt điểm ung nhọt cuối: nhân sự độc hại, khoản mù mờ, quy trình sai — đưa ra ánh sáng đúng kênh (họp chính thức, văn bản), không đấu tố bạo lực; cảnh giác phản đòn phút chót.",tc:"Cắt bỏ khoản đầu tư 'ung' cuối cùng trong danh mục — công khai minh bạch với đối tác liên quan; không dùng biện pháp cực đoan (kiện tụng ồ ạt) khi thương lượng còn cửa.",sk:"Loại trừ dứt điểm: cai hẳn thứ đang hại (thuốc lá, rượu), xử lý dứt khối viêm/nhọt theo chỉ định; nửa vời là tái phát — quẻ này không có chỗ cho 'giảm dần mãi mãi'."},
44:{tf:"«Người nữ mạnh, chớ vội cưới» — Gặp gỡ bất ngờ: một âm lẻn dưới năm dương; cám dỗ nhỏ sức lan lớn.",ty:"Người mới xuất hiện đầy quyến rũ và... đúng lúc một cách đáng ngờ; quẻ nhắc: sức hút mạnh không đồng nghĩa duyên lành — tìm hiểu kỹ gốc gác, đừng trao cam kết vội; người đang có đôi: cảnh giác 'gió lạ' lẻn vào.",cv:"Cơ hội gõ cửa bất ngờ, hấp dẫn khác thường — thẩm định gấp đôi bình thường; một yếu tố nhỏ (điều khoản, con người) có thể lớn dần chiếm quyền kiểm soát; gặp gỡ tình cờ vẫn có thể quý — nếu bạn tỉnh.",tc:"Món đầu tư 'ngon bất ngờ' xuất hiện: lãi cao, vào cửa dễ — đó chính là 'nữ tráng': đẹp mà đoạt quyền; kiểm tra pháp lý, dòng tiền, người đứng sau trước khi đặt một đồng.",sk:"Mầm bệnh nhỏ xâm nhập dễ lan (virus, nhiễm trùng): vệ sinh, khẩu trang, xử lý sớm từ dấu hiệu đầu; đừng xem thường triệu chứng 'bé tí' — quẻ này nói về cái nhỏ mà mạnh."},
45:{tf:"«Hanh thông, vua đến tông miếu; lợi gặp đại nhân, hanh, lợi bền chính; dùng lễ lớn thì cát, lợi khi có việc phải đi» — Tụ họp quanh đức lớn; chuẩn bị cả đề phòng.",ty:"Thời điểm ra mắt, họp mặt hai họ, tiệc tùng se duyên — các cuộc tụ đông mang duyên lành; quan hệ tiến tới bằng nghi lễ đàng hoàng ('dùng lễ lớn'); đông vui nhưng giữ nhau cẩn thận — chốn đông người lắm kẻ nhòm.",cv:"Gom lực tập thể: tổng động viên, hội nghị, gọi vốn cộng đồng — thời điểm quy tụ lòng người quanh mục tiêu xứng đáng; chuẩn bị kịch bản rủi ro: đám đông nào cũng có bất trắc.",tc:"Gọi vốn, gom quỹ thuận lợi; chi cho lễ nghĩa, sự kiện đúng mức là 'lễ lớn' sinh lộc; tiền đông người góp phải có quy chế chặt ngay từ đầu.",sk:"Sinh hoạt cộng đồng nâng tinh thần; nhưng chỗ đông người mùa dịch bệnh dễ lây — phòng vệ cá nhân; tránh 'vui quá độ' ở đám tiệc liên miên."},
46:{tf:"«Nguyên hanh; dùng gặp đại nhân, chớ lo; tiến về Nam thì cát» — Vươn lên như cây non trong đất: thăng tiến từng bước chắc chắn.",ty:"Tình cảm lớn dần đều — từ quen đến thân, từ thân đến sâu — đúng trình tự không đốt cháy; cứ mạnh dạn gặp gỡ người 'trên' (phụ huynh, người lớn) — quẻ bảo 'chớ lo'; hướng về phía sáng và ấm mà vun.",cv:"Thăng chức tuần tự: tích công từng việc, mỗi quý một bậc; mạnh dạn xin gặp cấp cao trình bày nguyện vọng — được tiếp đón; kiên trì như cây xuyên đất: mềm mà không gì cản nổi.",tc:"Tài sản tăng trưởng kiểu cây trồng: góp đều, lãi nhập gốc, thời gian làm việc của nó; thăng tiến thu nhập qua nâng cấp kỹ năng — đường 'phía Nam' sáng sủa của quẻ.",sk:"Tiến bộ chậm mà không lùi: phục hồi chức năng, tăng thể lực từng tuần; kiên nhẫn với tiến độ của cơ thể — cây không lớn nhanh hơn vì bị kéo."},
47:{tf:"«Hanh thông, bền chính; bậc đại nhân thì cát, không lỗi; có nói cũng không ai tin» — Khốn cùng: đầm cạn nước; giữ chí trong nghịch cảnh, nói ít làm nhiều.",ty:"Giai đoạn cạn kiệt cảm xúc — nói gì cũng bị hiểu sai ('có nói không ai tin'): tạm ngừng tranh luận, chuyển sang hành động nhỏ tử tế; giữ phẩm giá trong lúc khó — người cùng mình qua 'khốn' là người của cả đời.",cv:"Thời kẹt: tài nguyên cạn, tiếng nói mất trọng lượng; đừng thanh minh nhiều — làm việc lặng lẽ, kết quả sẽ nói thay; người giữ vững chí hướng qua thời này sẽ được 'đại nhân cát'.",tc:"Túng quẫn tài chính: co cụm về nhu cầu tối thiểu, giữ tín dụng cá nhân sạch (đúng hẹn dù ít); không vay nóng, không đầu tư 'gỡ' — đầm đang cạn, mọi giọt nước đều quý.",sk:"Kiệt sức thể chất lẫn tinh thần: giảm mọi tiêu hao không thiết yếu, ngủ là ưu tiên số một; trầm cảm là rủi ro thật của quẻ này — tìm hỗ trợ chuyên môn, đừng 'gồng trong im lặng'."},
48:{tf:"«Đổi ấp không đổi giếng; giếng không cạn không tràn; đến gần giếng mà chưa múc được, vỡ bình — hung» — Cái giếng: nguồn nuôi dưỡng chung; chăm nguồn và để người múc được.",ty:"Nguồn nuôi quan hệ (sự quan tâm, trò chuyện sâu) vẫn còn nguyên — chỉ là lâu rồi không ai 'thả gầu': chủ động múc lại — hỏi han thật, nghe thật; đừng để gần nhau mà 'vỡ bình' ở bước cuối vì vụng về.",cv:"Giá trị lõi của bạn (chuyên môn, uy tín) là cái giếng theo bạn qua mọi 'ấp' — mọi công ty; tu bổ nó: học lại, hệ thống lại; và để người khác 'múc được' — chia sẻ kiến thức tạo vị thế.",tc:"Nguồn thu bền (nghề chính, khách trung thành) cần được tái đầu tư — đừng mải đào giếng mới bỏ giếng đang trong; sản phẩm tốt mà không ai biết = giếng trong không người múc: làm marketing tử tế.",sk:"Chăm 'nguồn nước' cơ thể: uống đủ nước sạch, chăm thận — bể chứa của sức khoẻ; nếp cũ tốt từng có (môn thể thao xưa, giờ ngủ xưa) — quay lại múc từ giếng cũ ấy."},
49:{tf:"«Ngày Tị mới tin; nguyên hanh lợi trinh, hối hận tan mất» — Cách mạng: thay đổi lớn thành công khi đúng thời và được lòng tin.",ty:"Quan hệ cần cuộc 'cách mạng': đổi hẳn cách yêu, cách nói, cách phân vai — vá víu không đủ nữa; chọn đúng thời điểm ('ngày Tị mới tin' — khi lòng người đã sẵn) và làm trọn vẹn: đổi xong, mọi hối tiếc tan.",cv:"Chuyển đổi lớn: đổi nghề, tái cấu trúc, thay hệ thống; điều kiện thành công: thời điểm chín + niềm tin của những người liên quan — truyền thông kỹ trước khi đổi; đổi nửa vời nguy hơn không đổi.",tc:"Đại tu tài chính: đổi cấu trúc thu nhập, chuyển kênh đầu tư thời đại mới; hớt váng cái cũ trước khi nó mất giá — nhưng chờ tín hiệu xác nhận, không đổi theo cảm hứng.",sk:"Lột xác sức khoẻ: thay đổi lối sống toàn diện (bỏ hẳn — không phải bớt) khi cơ thể đã 'chín' cho thay đổi; các đợt thanh lọc, đổi chế độ ăn làm đúng thời điểm hiệu quả gấp bội."},
50:{tf:"«Nguyên cát, hanh thông» — Cái vạc: nấu chín, dưỡng hiền tài, lập nề nếp mới sau thay đổi.",ty:"Sau biến động là xây nếp mới: quy ước chung, tổ ấm được 'nấu' bằng lửa nhỏ đều — bữa cơm chung, giờ giấc chung; thời điểm đẹp để về chung nhà, lập bàn thờ tổ tiên, xây gia phong.",cv:"Dựng trật tự mới: quy trình, văn hoá, đào tạo người kế cận — bạn đang là 'cái vạc' nuôi hiền tài; vị trí quản lý – huấn luyện – nuôi dưỡng người khác vào độ chín nhất.",tc:"Cấu trúc tài chính mới vận hành ổn: quỹ, danh mục, dòng tiền vào nếp; đầu tư cho 'bếp lõi' (công cụ hành nghề, hệ thống) sinh lời lâu dài; giữ 'chân vạc' vững — ba trụ thu nhập là lý tưởng.",sk:"Ăn chín uống sôi — dinh dưỡng là trung tâm: nấu ăn tại nhà, thực phẩm tử tế; hệ tiêu hoá được chăm thì mọi thứ được nuôi; xây nếp sức khoẻ mới sau giai đoạn xáo trộn."},
51:{tf:"«Hanh thông; sấm đến kinh sợ rồi cười nói vui vẻ; sấm rung trăm dặm, không rơi thìa rượu tế» — Chấn động thức tỉnh: sợ mà không loạn thì trưởng thành.",ty:"Cú sốc tình cảm (tin bất ngờ, biến cố) làm rung chuyển — nhưng người giữ được 'thìa rượu tế' (sự trân trọng cốt lõi) sẽ thấy: sau sấm, không khí trong lành hơn; biến cố là tiếng chuông đánh thức điều hai người lãng quên.",cv:"Biến động ập đến (tin dữ, thay đổi đột ngột): phản xạ đúng là bình tĩnh giữ việc cốt lõi chạy đều; ai không loạn trong cơn sấm sẽ được nhìn nhận là thủ lĩnh; rà lại phương án khẩn cấp — sấm thường có dư chấn.",tc:"Thị trường rung lắc mạnh: không bán tháo trong hoảng loạn, không bắt đáy trong hưng phấn; người giữ kỷ luật qua cơn chấn động thường mua được giá tốt sau đó.",sk:"Chú ý tim mạch khi căng thẳng đột ngột, và hệ thần kinh (giật mình, hồi hộp, mất ngủ sau biến cố); tập thở, thiền định — luyện 'không rơi thìa rượu' cho hệ thần kinh."},
52:{tf:"«Ngừng ở lưng, không thấy thân mình; đi giữa sân, không thấy người; không lỗi» — Núi tĩnh lặng: dừng đúng chỗ cần dừng.",ty:"Tạm dừng là câu trả lời: ngừng truy vấn, ngừng níu, ngừng cả những suy diễn trong đầu; khoảng lặng chất lượng (mỗi người một góc yên) chữa được điều mà vạn lời nói không chữa nổi.",cv:"Biết dừng là chiến lược: dừng mở rộng, dừng nhận thêm, đứng yên củng cố; các quyết định 'không làm gì' lúc này chính là hành động đúng; hợp thời cho nghiên cứu sâu, viết lách, quy hoạch.",tc:"Ngừng giao dịch — đứng ngoài quan sát là vị thế tốt nhất; khoá bớt kênh tiêu tiền (app mua sắm, lướt sàn); tiền đứng yên đúng lúc là tiền đang làm việc.",sk:"Thiền, khí công, yoga — các môn 'tĩnh' vào thời vượng nhất; chú ý lưng và cột sống (Cấn = lưng): ngồi thẳng, giãn cơ lưng mỗi ngày; ngủ sâu là ưu tiên."},
53:{tf:"«Người con gái về nhà chồng, cát; lợi về sự bền chính» — Tiến dần dần: chim hồng bay từ bến lên cao theo thứ tự; đủ lễ, đủ bước.",ty:"Tình yêu đi đúng trình tự nở hoa bền: quen — hiểu — ra mắt — đính — cưới, không nhảy cóc; quẻ đại cát cho hôn nhân nghiêm túc; ai đang muốn 'nhanh cho xong' — quẻ này khuyên: chậm chính là nhanh.",cv:"Thăng tiến theo nấc: mỗi vị trí học trọn bài học của nó rồi mới lên; xây uy tín từng việc nhỏ đúng hạn; nhảy cóc lúc này dễ 'chim non gãy cánh' — từ chối lời mời vượt quá xa năng lực hiện tại.",tc:"Lộ trình tài sản từng bậc: quỹ khẩn cấp → bảo hiểm → tích sản → đầu tư tăng trưởng — đúng thứ tự đó; giàu chậm mà chắc là tinh thần của quẻ; cảnh giác mọi lời mời 'giàu tắt'.",sk:"Tiến độ từ từ: tăng tải tập luyện 5-10% mỗi tuần, giảm cân 0.5kg mỗi tuần — cơ thể chỉ giữ được thứ nó đạt được từ từ; phục hồi sau bệnh cũng leo từng bậc như chim hồng."},
54:{tf:"«Tiến tới thì hung, không có gì lợi» — Em gái theo về nhà chồng: kết hợp không đúng vị; biết phận mà giữ đức thì tránh được hối.",ty:"Cảnh báo về quan hệ lệch vị: yêu không danh phận, bị xem là 'phương án phụ', hoặc cưới gấp vì hoàn cảnh — tiến tới trong thế này chịu thiệt lâu dài; đòi hỏi sự rõ ràng về vị trí của mình, hoặc dừng lại.",cv:"Vị thế của bạn trong thương vụ/tổ chức đang là 'phận dưới không danh chính': hợp đồng miệng, vai trò mập mờ — đừng dấn sâu; nếu buộc phải tham gia, chấp nhận vai phụ một cách tỉnh táo và có thoả thuận rõ.",tc:"Không lợi cho giao kèo thế yếu: mua bán không giấy tờ, góp vốn không cổ phần rõ, đứng tên hộ — tất cả là 'quy muội': vào dễ, đòi quyền lợi thì khó; hoãn được thì hoãn.",sk:"Đừng phó thác sức khoẻ cho phương án tạm bợ: thuốc không rõ nguồn, thầy lang không phép; cơ thể xứng đáng 'danh chính': cơ sở y tế đàng hoàng, phác đồ minh bạch."},
55:{tf:"«Hanh thông, vua đến được; chớ lo, nên như mặt trời giữa trưa» — Thịnh đại: sấm và lửa cùng rực; toả sáng ngay bây giờ, biết trăng đầy sẽ khuyết.",ty:"Đỉnh cao rực rỡ của quan hệ: đám cưới lớn, kỷ niệm hoành tráng, giai đoạn 'mặt trời giữa trưa' — tận hưởng trọn, đừng vừa hạnh phúc vừa lo xa; chỉ cần gieo thói quen tốt ngay trong lúc thịnh để mùa sau vẫn ấm.",cv:"Vận sự nghiệp đạt cực thịnh: dự án lớn thành, tên tuổi vang — hành động lớn NGAY lúc trưa nắng, đừng chần chừ đến xế chiều; đồng thời lặng lẽ chuẩn bị lớp kế cận, hệ thống — cách người khôn đối đãi với đỉnh.",tc:"Doanh thu/danh mục đạt đỉnh chu kỳ: hiện thực hoá một phần thành quả (chốt lời, mua tài sản bền), đầu tư phần còn lại cho chu kỳ mới; xa hoa phô trương lúc đỉnh là gieo mầm cho lúc đáy.",sk:"Sinh lực đỉnh cao — lập thành tích thể chất được; nhưng 'trưa rồi sẽ xế': từ nay xây thói quen giữ gìn (khám định kỳ, ngủ đủ) để tuổi sau hưởng phúc của tuổi này."},
56:{tf:"«Hơi hanh thông; kẻ lữ hành bền chính thì cát» — Lữ khách nơi đất lạ: khiêm cung, gọn nhẹ, không gây chuyện.",ty:"Quan hệ giai đoạn 'tạm trú': mới chuyển vùng, yêu xa, hoặc cảm giác chưa thuộc về nhau trọn — đừng đòi hỏi sự ổn định ngay; lịch sự, chừng mực, quan sát; tình cảm nơi đất khách cần thời gian nhập tịch.",cv:"Vai trò mới, công ty mới, thị trường mới: bạn là khách — khiêm tốn học luật chơi bản địa, chưa vội cải cách; làm tốt việc nhỏ để lấy chỗ đứng; nghề xê dịch (du lịch, thương mại lưu động) hợp thời.",tc:"Tài chính kiểu lữ hành: gọn nhẹ, thanh khoản cao, không kẹt vốn vào thứ khó mang theo; chi tiêu nơi đất lạ dễ hớ — khảo giá trước; không phô của nơi không quen.",sk:"Giữ mình khi xa nhà: ăn chín uống sạch, bảo hiểm du lịch, thuốc men mang theo; cơ thể lạ nước lạ cái dễ rối loạn tiêu hoá, mất ngủ — giữ vài 'nghi thức quen' (giờ ngủ, bài tập) làm neo."},
57:{tf:"«Hơi hanh thông; lợi khi có việc phải đi, lợi gặp đại nhân» — Gió len lỏi: thuận nhập nhẹ nhàng, lặp lại mà thấm sâu.",ty:"Cảm hoá bằng mưa dầm: lời nhắc nhẹ, cử chỉ nhỏ lặp lại mỗi ngày thấm hơn một lần làm lớn; muốn người kia thay đổi — gieo gợi ý từ từ, đừng ra tối hậu thư; mềm mỏng là sức mạnh của thời này.",cv:"Thâm nhập từ từ: xây quan hệ, gây ảnh hưởng qua nhiều lần tiếp xúc nhỏ; thông điệp quan trọng phải nhắc lại nhiều lần nhiều kênh mới thấm; theo người dẫn dắt giỏi ('đại nhân') để gió có hướng.",tc:"Tiền vào theo kiểu gió: nhiều dòng nhỏ đều đặn (tích luỹ định kỳ, thu nhập phụ) hơn một cục lớn; đàm phán giá bằng nhiều vòng nhẹ nhàng thắng ép một lần.",sk:"Hô hấp là trọng tâm (Tốn = gió): tập thở sâu, khí công, giữ không khí trong lành; bệnh xâm nhập kiểu 'gió lùa' — cảm, dị ứng: giữ ấm cổ gáy, đề phòng gió lạnh."},
58:{tf:"«Hanh thông, lợi về sự bền chính» — Đầm nối đầm: niềm vui giao hoà; vui chính đáng thì dân quên nhọc.",ty:"Niềm vui là keo gắn: trò chuyện rôm rả, cười cùng nhau — quan hệ đang cần 'chơi' nhiều hơn 'giải quyết'; lời nói ngọt thật lòng (Đoài = miệng) hàn gắn nhanh; cảnh giác niềm vui giả lả bằng mặt không bằng lòng.",cv:"Không khí đội nhóm phấn khởi kéo hiệu suất: tổ chức trao đổi, học nhóm ('bạn bè cùng luyện tập' — tượng của quẻ); nghề nói năng (đào tạo, bán hàng, truyền thông) vượng; dẫn dắt bằng niềm vui, người theo quên mệt.",tc:"Tiền từ giao tiếp và dịch vụ niềm vui: ăn uống, giải trí, đào tạo; đàm phán trong không khí vui dễ chốt; nhưng vui không thay hợp đồng — cười xong vẫn ký giấy.",sk:"Niềm vui là thuốc bổ rẻ nhất: gặp bạn, ca hát, cười — miễn dịch tăng thật; chú ý vùng miệng – họng – phổi; cảnh giác 'vui quá đà': rượu bia tiệc tùng liên miên là mặt tối của Đoài."},
59:{tf:"«Hanh thông; vua đến tông miếu; lợi vượt sông lớn, lợi bền chính» — Tan rã cái đông cứng: gió thổi trên nước làm băng tan; hoà giải, quy tụ lại lòng người.",ty:"Băng giá giữa hai người đến kỳ tan: sự cứng đọng (giận lâu, chiến tranh lạnh) được thổi bằng gió ấm — một chuyến đi chung, một dự định lớn chung làm tan hết cái vụn; hy sinh cái tôi cho điều lớn hơn hai người.",cv:"Phá vỡ cục bộ, phe cánh bằng mục tiêu chung lớn lao: dự án toàn công ty, tầm nhìn mới; thời điểm tốt để hoà giải các nhóm, sáp nhập, tái kết nối đối tác cũ; việc lớn 'vượt sông' được quẻ ủng hộ.",tc:"Giải phóng tài sản đóng băng: bán tài sản kẹt, tách quỹ bị dồn cục, đa dạng hoá; dòng tiền cần được 'thổi' cho lưu thông — tiền tụ một chỗ quá lâu sinh trì trệ.",sk:"Khai thông là chìa khoá: tuần hoàn, bạch huyết, xoang — các chứng 'tắc' được trị tốt lúc này (xông, massage, vận động ra mồ hôi); tinh thần u uất cần 'gió': ra khỏi nhà, đổi không khí."},
60:{tf:"«Hanh thông; tiết chế khắc khổ thì không thể bền» — Chừng mực như đốt tre có mắt: có giới hạn thì không tràn, nhưng khổ hạnh quá thì hỏng.",ty:"Đặt 'mắt tre' cho quan hệ: giới hạn lành mạnh (giờ riêng, khoản riêng, lời không nói khi giận) làm tình bền; nhưng đừng biến kỷ luật thành khắc nghiệt — tiết chế để yêu dài lâu, không phải để hành nhau.",cv:"Làm việc có định mức: giờ giấc, phạm vi, cam kết vừa sức — nói 'không' với việc vượt ngưỡng là kỹ năng của thời này; quy chế rõ ràng cứu cả đội; nhưng quy định ngặt quá sẽ bị chính nó phá.",tc:"Ngân sách là trọng tâm: hạn mức từng khoản, tự động hoá tiết kiệm; sống dưới mức thu nhập nhưng đừng bần tiện với bản thân — 'khổ tiết' không bền, hãy tiết chế có niềm vui.",sk:"Điều độ là toa thuốc: ăn có giờ, làm có giấc, chơi có mức; kiêng khem cực đoan (nhịn quá, tập quá) phản tác dụng — cơ thể như tre: cần mắt để cứng, cần gióng để vươn."},
61:{tf:"«Lòng thành cảm được cả cá heo — cát; lợi vượt sông lớn, lợi bền chính» — Thành tín từ trong lòng: chân thành là sức mạnh vượt mọi hiểm.",ty:"Sự chân thành tuyệt đối là bùa yêu mạnh nhất lúc này: nói thật lòng mình — kể cả điều yếu đuối — sẽ chạm được nơi sâu nhất của người kia; lòng tin giữa hai người đủ 'cảm được cá heo' thì mọi thử thách chỉ là sông cạn.",cv:"Chữ tín là tài sản chiến lược: giữ đúng mọi cam kết dù nhỏ nhất; sự thành thật trong đàm phán (kể cả nhận điểm yếu) tạo lòng tin thắng mọi kỹ xảo; đội nhóm tin nhau dám 'vượt sông lớn'.",tc:"Tín dụng và uy tín tài chính: trả đúng hẹn, minh bạch số liệu — hồ sơ sạch mở mọi cánh cửa vốn; chỉ hợp tác với người có lịch sử giữ lời; lòng tham che mắt — lòng thành mở mắt.",sk:"Kết nối tâm – thân: các liệu pháp tinh thần (thiền, trị liệu tâm lý, viết nhật ký) tác động thẳng đến thể chất lúc này; thành thật với bản thân về tình trạng sức khoẻ — không tự dối, không giấu bác sĩ."},
62:{tf:"«Hanh thông, lợi bền chính; làm được việc nhỏ, không làm được việc lớn; chim bay để lại tiếng, không nên lên cao, nên xuống thấp — đại cát» — Quá nhỏ: thời chỉ hợp việc nhỏ, cung kính hơn, tiết kiệm hơn.",ty:"Thời của cử chỉ nhỏ: tin nhắn hỏi han, món quà bé, lời xin lỗi đúng lúc — đại cát; đừng làm màn lớn (cầu hôn hoành tráng, quyết định trọng đại) lúc này; 'bay thấp': khiêm nhường, sát đất, thực tế.",cv:"Chỉ nhận việc vừa tầm, làm chu đáo hơn mức yêu cầu — được đánh giá cao; kế hoạch tham vọng nên hạ độ cao: chia thành mục tiêu nhỏ; chi tiết là nơi thắng cuộc của thời này, đừng vươn quá tay với.",tc:"Giao dịch nhỏ, chắc; khoản lớn hoãn lại; tiết kiệm hơn thường lệ một bậc; lợi nhuận nhỏ đều đặn là 'đại cát' của quẻ — chê nhỏ mà với lớn sẽ 'chim bay gặp nạn'.",sk:"Chăm chút triệu chứng nhỏ chu đáo hơn bình thường: vết xước, cơn đau nhẹ — xử lý ngay; vận động nhẹ nhàng sát đất (đi bộ, bơi chậm), tránh môn mạo hiểm độ cao; cẩn tắc vô ưu là toa của quẻ."},
63:{tf:"«Hanh thông việc nhỏ, lợi bền chính; ban đầu cát, cuối cùng loạn» — Đã hoàn thành: nồi cơm đã chín; củng cố phòng ngừa, chớ ngủ quên.",ty:"Quan hệ đạt trạng thái 'mọi thứ vào vị trí': ổn định, nề nếp — đẹp, nhưng quẻ cảnh báo 'sơ cát chung loạn': sự chủ quan sau khi 'đã xong' là kẻ phá hoại số một; tiếp tục hẹn hò như thuở đầu, đừng chuyển sang 'chế độ mặc định'.",cv:"Dự án hoàn tất tốt đẹp: nghiệm thu, tổng kết, lưu bài học — làm kỹ khâu hậu kỳ; cảnh giác cao nhất sau thành công: lỗi hậu vận hành, đối thủ phản công; đặt hệ thống giám sát trước khi ăn mừng.",tc:"Mục tiêu tài chính đã đạt: chốt và bảo toàn — chuyển một phần sang tài sản an toàn; nguy cơ lớn nhất là 'thừa thắng xông lên' thiếu tính toán; kỷ luật sau chiến thắng khó hơn kỷ luật khi khó khăn.",sk:"Bệnh vừa khỏi, chỉ số vừa đẹp — giai đoạn dễ tái phát nhất chính là đây: duy trì thuốc/liệu trình đủ ngày, giữ nếp đã tạo; sức khoẻ 'đã tế' vẫn cần canh lửa nhỏ."},
64:{tf:"«Hanh thông; cáo nhỏ qua gần hết sông, ướt cái đuôi — không gì lợi» — Chưa hoàn thành: còn đoạn cuối; thận trọng gấp đôi ở bước chót.",ty:"Sắp đến bến mà chưa đến: quan hệ đang tiến tới cột mốc (ngỏ lời, ra mắt, cưới) — chính lúc này dễ 'ướt đuôi' vì chủ quan; đi nốt đoạn cuối bằng sự cẩn trọng của đoạn đầu; chưa xong thì chưa phải lúc kể công.",cv:"Dự án 90%: rà từng hạng mục còn lại, phân định rõ ai làm gì ('phân biệt vật ở đúng chỗ' — tượng quẻ); đừng công bố sớm, đừng rút quân sớm; bài học con cáo: cẩn thận đến giọt nước cuối cùng.",tc:"Thương vụ chưa ký xong là chưa có gì: không tiêu trước khoản chưa về, không cam kết mới dựa trên tiền tương lai; giai đoạn chuyển tiếp tài chính — giữ thanh khoản dày hơn bình thường.",sk:"Liệu trình chưa xong đừng bỏ giữa chừng — 'gần khỏi' là lúc bỏ thuốc nhiều nhất và tái phát nhiều nhất; kiểm tra lại lần cuối trước khi kết luận khỏi; kiên nhẫn nốt chặng chót."}
};

/* Ý nghĩa vị trí 6 hào (đọc hào động theo phép chiêm thông dụng) */
const HAO_Y=[
"Hào Sơ (dưới cùng) — khởi đầu của sự việc: biến động nằm ở giai đoạn đầu, ở người mới, việc mới; nên cẩn trọng đặt nền, chưa vội tiến sâu.",
"Hào Nhị — bề tôi hiền ở trung vị: biến động ở người thực thi, việc bên trong; thường là hào tốt — giữ trung chính, làm tròn vai sẽ được đáp.",
"Hào Tam — chỗ giáp ranh trong–ngoài: biến động ở bước chuyển tiếp, dễ sinh sai lầm vì nóng vội; cân nhắc kỹ trước khi bước qua ngưỡng.",
"Hào Tứ — cận kề bậc trên: biến động liên quan cấp trên, đối tác lớn; nên khiêm cung thăm dò, tiến thoái mềm dẻo.",
"Hào Ngũ — ngôi vua, trung chính tôn quý: biến động ở người quyết định, ở đại cục; thường là hào chủ đạo — điềm về vai trò lãnh đạo, quyết sách lớn.",
"Hào Thượng (trên cùng) — cực điểm của thời: sự việc đã tới đỉnh, sắp chuyển hoá; chớ cố thêm — vật cực tất phản, nên tính đường lui hoặc chuyển hướng."
];

